INSERT INTO `tb_dokumentasi` (`id`, `title`, `desk`, `img`, `date`) VALUES
(1, 'Kegiatan EKSOTIK', '<ul>\r\n      <li>Foto di atas memperlihatkan suasana <b>kegiatan pembelajaran</b> yang berlangsung di ruang kelas.</li>\r\n      <li>Kegiatan ini diisi oleh <b>pemateri/dosen</b> yang sedang menyampaikan materi di depan kelas.\r\n        <ul>\r\n          <li>Para peserta/mahasiswa mengikuti dengan penuh <i>antusias</i> dan tetap tertib.</li>\r\n          <li>Seluruh peserta duduk dengan rapi serta memperhatikan penjelasan yang diberikan secara serius.</li>\r\n          <li>Interaksi antara pemateri dan peserta menciptakan suasana belajar yang lebih hidup.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Fasilitas ruang kelas mendukung kegiatan pembelajaran dengan baik:\r\n        <ul>\r\n          <li>Pencahayaan yang terang sehingga membuat ruangan nyaman.</li>\r\n          <li><b>Proyektor</b> untuk presentasi, membantu penyampaian materi lebih jelas dan menarik.</li>\r\n          <li>Tata ruang yang tertata rapi sehingga memudahkan peserta untuk fokus.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dokumentasi ini menunjukkan bahwa kegiatan:\r\n        <ul>\r\n          <li>Berlangsung dengan <b>lancar</b> sesuai rencana yang telah disusun.</li>\r\n          <li>Memiliki nuansa <i>interaktif</i>, di mana peserta tidak hanya mendengarkan tetapi juga berpartisipasi dalam diskusi.</li>\r\n          <li>Sesuai dengan tujuan utama untuk menciptakan suasana belajar yang kondusif, efektif, dan menyenangkan.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dari dokumentasi ini juga terlihat bahwa:\r\n        <ul>\r\n          <li>Peserta mampu menjaga sikap disiplin dan aktif selama pembelajaran.</li>\r\n          <li>Pemateri berhasil menyampaikan materi dengan gaya komunikasi yang mudah dipahami.</li>\r\n          <li>Kegiatan semacam ini dapat menjadi contoh baik bagi proses pembelajaran di kesempatan berikutnya.</li>\r\n        </ul>\r\n      </li>\r\n    </ul>', '/assets/dokumentasi/eksotik_23_10_24_(1).jpeg', '2024-10-23'),
(2, 'Kegiatan EKSOTIK', '    <ul>\r\n      <li>Foto ini mendokumentasikan kegiatan <b>EKSOTIK Pojok Statistik UNIBA</b> yang dilaksanakan pada <b>Desember 2024</b>.</li>\r\n      <li>Terlihat <b>pemateri</b> sedang menyampaikan materi di depan kelas dengan menggunakan perangkat presentasi.\r\n        <ul>\r\n          <li>Para peserta mengikuti penyampaian dengan penuh <i>keseriusan</i> dan <i>antusiasme</i>.</li>\r\n          <li>Pemateri memanfaatkan <b>slide presentasi</b> untuk menjelaskan konsep statistik secara lebih jelas.</li>\r\n          <li>Interaksi antara pemateri dan peserta berjalan baik melalui sesi tanya jawab singkat.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Suasana ruang kelas mendukung jalannya kegiatan:\r\n        <ul>\r\n          <li>Tata ruang yang rapi membuat peserta nyaman dalam mengikuti pembelajaran.</li>\r\n          <li>Fasilitas seperti <b>proyektor</b>, pencahayaan yang cukup, dan kursi yang tertata mendukung proses belajar.</li>\r\n          <li>Lingkungan kelas yang kondusif mendorong fokus dan konsentrasi penuh peserta.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dokumentasi ini menunjukkan bahwa kegiatan:\r\n        <ul>\r\n          <li>Berlangsung dengan <b>lancar</b> sesuai rencana yang telah disusun.</li>\r\n          <li>Memiliki nuansa <i>interaktif</i> dengan partisipasi aktif mahasiswa.</li>\r\n          <li>Memberikan <b>manfaat akademik</b> berupa pemahaman tambahan terkait literasi statistik.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dari kegiatan ini dapat disimpulkan bahwa:\r\n        <ul>\r\n          <li>Peserta tidak hanya memperoleh teori, tetapi juga pengalaman belajar yang aplikatif.</li>\r\n          <li>Kegiatan <i>EKSOTIK Pojok Statistik</i> berperan penting dalam menumbuhkan minat mahasiswa terhadap data.</li>\r\n          <li>Acara ini menjadi sarana yang efektif untuk menghubungkan materi statistik dengan praktik di lapangan.</li>\r\n        </ul>\r\n      </li>\r\n    </ul>', '/assets/dokumentasi/eksotik_10_12_24_(2).jpeg', '2024-12-10'),
(3, 'Rapat Pojok Statistik', '<ul>\r\n      <li>Foto ini mendokumentasikan kegiatan <b>rapat</b> yang dilaksanakan di ruang <b>Pojok Statistik Universitas Bina Bangsa (UNIBA)</b>.</li>\r\n      <li>Terlihat beberapa peserta rapat sedang berdiskusi secara serius.\r\n        <ul>\r\n          <li>Topik utama pembahasan adalah <b>pengembangan program</b> serta pemanfaatan fasilitas <i>Pojok Statistik</i>.</li>\r\n          <li>Pojok Statistik dipandang sebagai <b>pusat pembelajaran data</b> dan peningkatan literasi statistik di lingkungan kampus.</li>\r\n          <li>Diskusi berlangsung dengan suasana yang terbuka, di mana setiap peserta dapat menyampaikan gagasan dan masukan.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Latar belakang ruangan menampilkan identitas <i>Pojok Statistik</i>:\r\n        <ul>\r\n          <li>Terdapat berbagai <b>poster informasi</b> yang berisi edukasi tentang data dan statistik.</li>\r\n          <li>Papan nama resmi memperkuat identitas ruang sebagai bagian dari kerja sama BPS dengan universitas.</li>\r\n          <li>Tata ruang sederhana namun tetap memberikan nuansa akademik yang kuat.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dokumentasi ini menunjukkan bahwa rapat:\r\n        <ul>\r\n          <li>Berlangsung dalam suasana <b>kondusif</b> dan penuh semangat kolaborasi.</li>\r\n          <li>Menunjukkan komunikasi yang <i>komunikatif</i> antara peserta dari berbagai latar belakang.</li>\r\n          <li>Berorientasi pada penguatan kegiatan akademik dan literasi statistik di kampus.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dari kegiatan ini dapat ditarik beberapa poin penting:\r\n        <ul>\r\n          <li>Adanya komitmen bersama untuk menjadikan <i>Pojok Statistik</i> sebagai ruang belajar yang aktif dan produktif.</li>\r\n          <li>Keseriusan peserta rapat mencerminkan dukungan penuh terhadap upaya peningkatan literasi data di kalangan mahasiswa.</li>\r\n          <li>Kegiatan ini juga menjadi bukti nyata kolaborasi antara BPS dan perguruan tinggi dalam membangun ekosistem akademik berbasis data.</li>\r\n        </ul>\r\n      </li>\r\n    </ul>', '/assets/dokumentasi/rapat_potik.jpeg', '2025-03-15'),
(4, 'Pembinaan Agen Pojok Statistik', ' <ul>\r\n      <li>Foto ini mendokumentasikan kegiatan <b>Pembinaan Agen Pojok Statistik</b> yang diselenggarakan pada <b>November 2024</b>.</li>\r\n      <li>Kegiatan berlangsung di ruang kelas dengan suasana yang <b>kondusif</b>.\r\n        <ul>\r\n          <li><b>Narasumber</b> berdiri di depan ruangan memberikan arahan dan materi pembinaan kepada peserta.</li>\r\n          <li>Materi yang disampaikan mencakup penguatan peran agen dalam mendukung <i>literasi statistik</i> di kampus.</li>\r\n          <li>Peserta diberikan kesempatan untuk berdiskusi, bertanya, dan berbagi pengalaman lapangan.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Para <b>agen Pojok Statistik</b> tampak antusias dan aktif mengikuti kegiatan.\r\n        <ul>\r\n          <li>Antusiasme terlihat dari respon cepat terhadap pertanyaan dan aktivitas kelompok.</li>\r\n          <li>Peserta menunjukkan <i>semangat belajar</i> yang tinggi untuk meningkatkan kapasitas diri.</li>\r\n          <li>Diskusi interaktif membantu peserta memahami peran penting agen statistik di kampus.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dokumentasi ini menunjukkan bahwa kegiatan pembinaan:\r\n        <ul>\r\n          <li>Berjalan dengan <b>baik</b> sesuai dengan rencana yang telah disusun.</li>\r\n          <li>Memiliki suasana <i>interaktif</i> antara narasumber dan peserta.</li>\r\n          <li>Sesuai dengan tujuan utama yaitu penguatan kompetensi agen <i>Pojok Statistik</i>.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dari kegiatan ini dapat disimpulkan bahwa:\r\n        <ul>\r\n          <li>Agen Pojok Statistik semakin siap berperan sebagai <b>penyambung literasi data</b> di lingkungan akademik.</li>\r\n          <li>Kegiatan pembinaan semacam ini menjadi wadah penting untuk meningkatkan keterampilan komunikasi data.</li>\r\n          <li>Program berkelanjutan akan memperkuat kontribusi agen dalam mendukung pemanfaatan data statistik secara luas.</li>\r\n        </ul>\r\n      </li>\r\n    </ul>', '/assets/dokumentasi/pembinaan_agen_11_24.jpeg', '2025-03-20'),
(5, 'Pembinaan Desain Publikasi', '<ul>\r\n      <li>Foto ini mendokumentasikan kegiatan <b>Pembinaan Agen Pojok Statistik</b> yang difokuskan pada <b>pembuatan layout desain publikasi</b> dan <b>infografis</b>.</li>\r\n      <li>Dalam kegiatan ini, peserta mendapatkan bimbingan langsung dari <b>pendamping</b>.\r\n        <ul>\r\n          <li>Peserta diarahkan untuk memahami teknik penyusunan desain publikasi berbasis data.</li>\r\n          <li>Pendamping menekankan pentingnya menyajikan informasi dalam bentuk <i>infografis</i> yang menarik dan mudah dipahami.</li>\r\n          <li>Materi pelatihan mencakup pengenalan prinsip desain, pemilihan warna, tipografi, serta tata letak visual.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Para <b>agen Pojok Statistik</b> terlihat aktif dalam kegiatan.\r\n        <ul>\r\n          <li>Mereka berdiskusi mengenai cara menyajikan data agar lebih komunikatif.</li>\r\n          <li>Peserta mencatat poin-poin penting yang disampaikan oleh pendamping.</li>\r\n          <li>Latihan praktik menggunakan <i>materi pendukung</i> membantu memperkuat pemahaman teknis.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dokumentasi ini menunjukkan suasana pembinaan yang <b>interaktif</b> dan <b>kreatif</b>.\r\n        <ul>\r\n          <li>Kegiatan mendorong kolaborasi antara peserta dalam menghasilkan karya desain.</li>\r\n          <li>Terdapat sesi umpan balik langsung agar peserta dapat memperbaiki hasil desain mereka.</li>\r\n          <li>Fasilitas yang tersedia, seperti komputer dan proyektor, mendukung kelancaran pembelajaran.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Tujuan kegiatan ini adalah untuk:\r\n        <ul>\r\n          <li>Meningkatkan <b>keterampilan agen</b> dalam mengolah data menjadi informasi visual yang mudah dipahami.</li>\r\n          <li>Mendorong agen agar mampu menyebarluaskan informasi statistik dengan cara yang lebih <i>informatif</i> dan <i>atraktif</i>.</li>\r\n          <li>Memperkuat peran Pojok Statistik sebagai pusat literasi data di lingkungan akademik.</li>\r\n        </ul>\r\n      </li>\r\n    </ul>', '/assets/dokumentasi/pembinaan_agen_LayoutDesignPublikasi.jpeg', '2024-09-01'),
(6, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Pandeglang Tahap 1', '<ul>\r\n      <li>Acara dimulai dengan <b>pembukaan</b> oleh <b>Lurah Juhut, Muhamad Syahrul</b>, kemudian dilanjutkan pemaparan materi dari <b>tim Desa Cantik BPS Kabupaten Pandeglang</b>.</li>\r\n      <li>Materi utama menekankan pentingnya peran desa:\r\n        <ul>\r\n          <li>Desa dipandang sebagai <b>subyek sekaligus ujung tombak pembangunan</b>.</li>\r\n          <li><b>Penguatan literasi</b> dan <b>pengelolaan data</b> menjadi kunci pembangunan yang tepat sasaran.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Program <b>Desa Cantik</b> memiliki tujuan utama:\r\n        <ul>\r\n          <li>Meningkatkan literasi statistik perangkat desa dan masyarakat.</li>\r\n          <li>Menstandardisasi sistem <i>pengelolaan data</i> agar lebih terstruktur.</li>\r\n          <li>Mengoptimalkan pemanfaatan data untuk perencanaan pembangunan.</li>\r\n          <li>Membentuk <b>agen statistik</b> sebagai aktor utama di desa.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Tahapan pelaksanaan program mencakup:\r\n        <ul>\r\n          <li>Koordinasi awal dengan perangkat desa.</li>\r\n          <li>Identifikasi potensi dan kebutuhan desa.</li>\r\n          <li>Penyusunan perencanaan kegiatan.</li>\r\n          <li>Pelaksanaan dengan rujukan pada <i>Sistem Statistik Nasional (SSN)</i> dan <i>Generic Statistical Business Process Model (GSBPM)</i>.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Output yang ditargetkan antara lain:\r\n        <ul>\r\n          <li><b>Monografi desa</b> yang berisi profil lengkap desa.</li>\r\n          <li><b>Publikasi Desa dalam Angka</b> sebagai sumber informasi statistik resmi.</li>\r\n          <li><i>Infografis</i> untuk menyajikan data secara visual dan menarik.</li>\r\n          <li>Meningkatnya kemampuan <b>agen statistik</b> dalam menyajikan data.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Dalam sesi diskusi, ditegaskan beberapa poin penting:\r\n        <ul>\r\n          <li><b>Agen statistik</b> tidak memperoleh honor finansial, namun perannya sangat penting bagi keberhasilan program.</li>\r\n          <li>Agen statistik diutamakan berasal dari perangkat desa dengan jumlah ditentukan oleh kepala desa.</li>\r\n          <li>Penerapan standar internasional <i>GSBPM</i> dilakukan secara bertahap.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Program <b>Desa Cantik</b> memiliki batasan:\r\n        <ul>\r\n          <li>Tidak mencakup otomatisasi sistem secara langsung.</li>\r\n          <li>Tidak termasuk pengadaan barang, melainkan fokus pada peningkatan kapasitas <i>SDM</i>.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Status pelaksanaan program:\r\n        <ul>\r\n          <li>Beberapa desa telah memiliki <b>SK agen statistik</b>.</li>\r\n          <li>Pembinaan lanjutan dijadwalkan secara fleksibel sesuai kebutuhan dan kesepakatan bersama.</li>\r\n          <li>Kerja sama BPS dengan desa berlangsung hingga <b>Oktober 2024</b>, namun pendampingan tetap dapat diminta meski di luar periode program.</li>\r\n        </ul>\r\n      </li>\r\n    </ul>', '/assets/dokumentasi/pembinaanDCpandeglang1.jpg', '2025-05-09'),
(7, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Pandeglang Tahap 2', ' <ul>\r\n      <li>Acara dimoderatori oleh <b>Fajar Sidik Karimulloh</b> dari tim <b>Desa Cantik BPS Pandeglang</b>, dengan materi utama mencakup:\r\n        <ul>\r\n          <li><b>Metadata Statistik</b></li>\r\n          <li><b>Satu Data Desa Indonesia</b></li>\r\n          <li><b>Identifikasi Kebutuhan Desa</b></li>\r\n        </ul>\r\n      </li>\r\n      <li><b>Metadata Statistik</b> dijelaskan sebagai informasi yang menggambarkan data secara detail:\r\n        <ul>\r\n          <li>Mencakup terminologi, definisi, klasifikasi, lokasi, metodologi, dan publikasi.</li>\r\n          <li>Memiliki manfaat berbeda bagi pembina, produsen, wali, dan pengguna data.</li>\r\n          <li>Manfaat metadata antara lain:\r\n            <ul>\r\n              <li>Meningkatkan efisiensi pengelolaan data.</li>\r\n              <li>Menghindari duplikasi pencatatan.</li>\r\n              <li>Mencegah terjadinya kesalahan.</li>\r\n              <li>Memudahkan pemahaman dan penggunaan data.</li>\r\n            </ul>\r\n          </li>\r\n        </ul>\r\n      </li>\r\n      <li><b>Identifikasi kebutuhan desa</b> menjadi tahap awal Program Desa Cantik.\r\n        <ul>\r\n          <li>Tujuannya untuk mengetahui profil, potensi, masalah, serta program yang diperlukan desa.</li>\r\n          <li>Metode yang digunakan:\r\n            <ul>\r\n              <li>Wawancara langsung dengan perangkat desa.</li>\r\n              <li>Forum diskusi bersama masyarakat desa.</li>\r\n              <li>Instrumen online yang dikirimkan ke BPS.</li>\r\n            </ul>\r\n          </li>\r\n        </ul>\r\n      </li>\r\n      <li>Kegiatan juga dilanjutkan dengan <b>pendampingan pengisian tabel publikasi output Desa Cantik 2025</b>.</li>\r\n      <li>Dalam sesi diskusi, dibahas berbagai topik:\r\n        <ul>\r\n          <li>Contoh dokumen metadata yang digunakan dalam praktik.</li>\r\n          <li>Perbedaan pencatatan penduduk:\r\n            <ul>\r\n              <li><i>Defacto</i> (versi BPS)</li>\r\n              <li><i>Dejure</i> (versi Disdukcapil)</li>\r\n            </ul>\r\n          </li>\r\n          <li>Pentingnya menghindari duplikasi data meskipun tidak ada larangan tertulis.</li>\r\n        </ul>\r\n      </li>\r\n      <li><b>Pengisian form identifikasi</b> dilakukan secara bertahap sesuai ketersediaan data desa.\r\n        <ul>\r\n          <li>Untuk metadata diperlukan akun yang dikoordinasikan dengan kecamatan dan Diskominfo.</li>\r\n        </ul>\r\n      </li>\r\n      <li><b>Publikasi data desa</b> diharapkan selengkap mungkin.\r\n        <ul>\r\n          <li>Desa diminta melengkapi data tambahan dari pihak terkait.</li>\r\n          <li>Contoh pihak yang dapat dimintai data tambahan:\r\n            <ul>\r\n              <li><b>Puskesmas</b></li>\r\n              <li><b>Bidan desa</b></li>\r\n            </ul>\r\n          </li>\r\n          <li>Hal ini bertujuan agar publikasi lebih komprehensif dan bermanfaat.</li>\r\n        </ul>\r\n      </li>\r\n    </ul>', '/assets/dokumentasi/pembinaanDCpandeglang2.jpg', '2025-05-20'),
(8, 'Pencanangan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak', ' <ul>\r\n      <li>Pada <b>28 April 2025</b>, <b>Desa Sumurbandung</b> resmi dicanangkan sebagai <b>Desa Cantik 2025</b>, menandai dimulainya program pembinaan desa untuk meningkatkan kualitas dan kesejahteraan masyarakat.</li>\r\n      <li>Acara ini dihadiri oleh berbagai <b>Organisasi Perangkat Daerah (OPD)</b> dan tokoh masyarakat:\r\n        <ul>\r\n          <li>Dinas Komunikasi dan Informatika (<i>Kominfo</i>), Badan Perencanaan Pembangunan, dan <b>DPMD</b>.</li>\r\n          <li><b>Camat Cikulur</b>, Babinsa, dan Bhabinkamtibmas.</li>\r\n          <li>Tokoh masyarakat, tokoh agama, serta ketua RT/RW setempat.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Rangkaian acara dimulai dengan <b>pembukaan</b> yang dipandu oleh <b>Master of Ceremony (MC)</b>.\r\n        <ul>\r\n          <li>MC menyampaikan ucapan selamat datang kepada seluruh tamu undangan.</li>\r\n          <li>MC juga menjelaskan tujuan kegiatan, yaitu pencanangan program <b>Desa Cantik</b> untuk meningkatkan pengelolaan data desa.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Acara dilanjutkan dengan arahan dari <b>Camat Cikulur</b>.\r\n        <ul>\r\n          <li>Camat menekankan pentingnya <b>sinergi</b> antara pemerintah desa, kecamatan, dan BPS.</li>\r\n          <li>Optimalisasi pemanfaatan data disebut sebagai kunci <i>perencanaan pembangunan tepat sasaran</i>.</li>\r\n        </ul>\r\n      </li>\r\n      <li><b>Kepala Desa Sumurbandung</b> kemudian memberikan sambutan.\r\n        <ul>\r\n          <li>Menyampaikan terima kasih atas kepercayaan yang diberikan kepada desanya sebagai desa binaan program Desa Cantik.</li>\r\n          <li>Menegaskan komitmen perangkat desa untuk aktif mengikuti pembinaan.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Acara berlanjut dengan paparan dari <b>Kepala BPS Kabupaten Lebak</b>.\r\n        <ul>\r\n          <li>Menjelaskan konsep dan tujuan program Desa Cantik.</li>\r\n          <li>Memaparkan manfaat yang akan diperoleh desa bila mampu mengelola data secara <b>akurat</b>, <b>mutakhir</b>, dan <b>berkelanjutan</b>.</li>\r\n        </ul>\r\n      </li>\r\n      <li>Sebagai penutup sesi sambutan, <b>Ketua Tim Pembina Desa Cantik BPS Provinsi Banten</b> menyampaikan materi pembinaan.\r\n        <ul>\r\n          <li>Menjelaskan peran BPS Provinsi dalam mendukung pembinaan Desa Cantik di seluruh wilayah Banten.</li>\r\n          <li>Strategi pendampingan, penyediaan instrumen, serta penguatan kapasitas aparatur desa menjadi fokus utama.</li>\r\n        </ul>\r\n      </li>\r\n      <li><b>Puncak acara</b> adalah pencanangan resmi oleh <b>Kepala Dinas DPMD Kabupaten Lebak</b>.\r\n        <ul>\r\n          <li>Momen ini menjadi tonggak penting bagi Desa Sumurbandung dalam upaya menjadi desa yang lebih maju, mandiri, dan berbasis data.</li>\r\n          <li>Dukungan dari semua pihak diharapkan dapat membawa perubahan positif bagi desa dan masyarakat di masa depan.</li>\r\n        </ul>\r\n      </li>\r\n    </ul>', '/assets/dokumentasi/penancanganDClebak.png', '2025-04-28'),
(9, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak Tahap 1: Identifikasi Kebutuhan Data', '<p>Pada tanggal <b>30 April 2025</b> telah dilaksanakan kegiatan <i>Pembinaan Desa Cantik</i> di Desa Sumurbandung. \r\n      Kegiatan ini membahas materi <i>Identifikasi Kebutuhan Data</i> yang bertujuan untuk membantu desa memahami berbagai jenis serta sumber data yang diperlukan dalam proses <b>perencanaan pembangunan</b>. \r\n      Melalui pembinaan ini, para peserta didorong untuk lebih sadar akan pentingnya pengelolaan data yang sistematis dan berkesinambungan, karena data menjadi dasar utama dalam merancang program desa yang efektif.</p>\r\n\r\n      <p>Peserta memperoleh penjelasan yang cukup komprehensif tentang:</p>\r\n      <ul>\r\n        <li><b>Pentingnya data yang akurat dan terbarukan</b>\r\n          <ul>\r\n            <li>Data yang valid dapat mendukung <i>transparansi</i> dan akuntabilitas desa.</li>\r\n            <li>Informasi yang mutakhir membantu perangkat desa mengambil keputusan yang sesuai dengan kondisi terkini.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Teknik mengidentifikasi data prioritas</b>\r\n          <ul>\r\n            <li>Menentukan data mana yang paling mendesak untuk kebutuhan pembangunan.</li>\r\n            <li>Mengelompokkan data berdasarkan bidang, misalnya kesehatan, pendidikan, atau ekonomi lokal.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Pemanfaatan data dalam mendukung kebijakan desa</b>\r\n          <ul>\r\n            <li>Data digunakan sebagai <i>bukti nyata</i> dalam penyusunan rencana kerja tahunan.</li>\r\n            <li>Membantu desa dalam menyusun program yang tepat sasaran dan menghindari kebijakan yang tidak relevan.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Melalui pembinaan ini, diharapkan perangkat desa mampu:</p>\r\n      <ul>\r\n        <li>Menyusun <b>daftar kebutuhan data</b> yang sesuai dengan potensi lokal dan permasalahan wilayah.</li>\r\n        <li>Mengembangkan kemampuan dalam <i>analisis sederhana</i> untuk memahami tren dari data yang dimiliki.</li>\r\n        <li>Mewujudkan pengelolaan data desa yang lebih terarah, terstruktur, serta bermanfaat bagi peningkatan kualitas layanan masyarakat.</li>\r\n      </ul>\r\n\r\n      <p>Pada akhirnya, kegiatan ini tidak hanya memperkaya pengetahuan peserta, tetapi juga menegaskan bahwa <b>data merupakan aset strategis</b> bagi desa. \r\n      Dengan dukungan semua pihak, pengelolaan data yang baik akan menjadi pondasi penting untuk menciptakan pembangunan desa yang lebih maju, mandiri, dan berkelanjutan.\r\n    </p>', '/assets/dokumentasi/pembinaanDClebak1.png', '2025-04-30'),
(10, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak Tahap 2: Teknik Pengumpulan Data', '<p>Pada tanggal <b>7 Mei 2025</b>, di Desa Sumurbandung telah dilaksanakan kegiatan <i>Pembinaan Desa Cantik</i> dengan materi utama <b>Teknik Pengumpulan Data</b>. \r\n      Kegiatan ini bertujuan untuk meningkatkan kemampuan perangkat desa dalam mengumpulkan data secara <b>efektif</b>, <b>akurat</b>, dan sesuai standar yang telah ditetapkan oleh lembaga resmi. \r\n      Data yang baik dan terstruktur akan menjadi fondasi penting bagi desa untuk menyusun program pembangunan yang berdaya guna.</p>\r\n\r\n      <p>Peserta mendapatkan pemahaman mengenai berbagai metode pengumpulan data, antara lain:</p>\r\n      <ul>\r\n        <li><b>Survei</b>\r\n          <ul>\r\n            <li>Digunakan untuk menjangkau banyak responden sekaligus dalam waktu relatif singkat.</li>\r\n            <li>Membantu memperoleh gambaran umum mengenai kondisi sosial, ekonomi, maupun demografi desa.</li>\r\n            <li>Jika dirancang dengan baik, survei dapat menghasilkan informasi yang representatif dan dapat dipertanggungjawabkan.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Wawancara</b>\r\n          <ul>\r\n            <li>Memberikan kesempatan untuk menggali informasi lebih mendalam dari responden tertentu.</li>\r\n            <li>Cocok untuk mengumpulkan data kualitatif yang memerlukan penjelasan detail dan narasi pengalaman.</li>\r\n            <li>Teknik ini sangat membantu ketika desa ingin memahami persoalan yang tidak dapat diukur hanya dengan angka.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Observasi</b>\r\n          <ul>\r\n            <li>Melibatkan pengamatan langsung terhadap kondisi lapangan, lingkungan, maupun aktivitas masyarakat.</li>\r\n            <li>Bermanfaat untuk melengkapi data survei dan wawancara dengan bukti nyata yang lebih objektif.</li>\r\n            <li>Observasi juga membantu memvalidasi data yang diperoleh dari sumber lain, sehingga hasilnya lebih meyakinkan.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Selain memahami metode, peserta juga mendapatkan penjelasan tentang aspek penting dalam pelaksanaan pengumpulan data, seperti:</p>\r\n      <ul>\r\n        <li><b>Menentukan responden</b> yang tepat sesuai kebutuhan data dan tujuan pembangunan desa.</li>\r\n        <li><b>Menyusun instrumen</b> seperti kuesioner, daftar pertanyaan, atau pedoman wawancara agar pengumpulan data lebih terarah dan tidak menyimpang dari sasaran.</li>\r\n        <li><b>Menjaga etika</b> dalam proses pengumpulan data, termasuk menghargai privasi responden dan menjelaskan tujuan penelitian secara transparan.</li>\r\n      </ul>\r\n\r\n      <p>Melalui pembinaan ini, diharapkan perangkat desa mampu memperoleh data yang <b>valid</b>, <b>mutakhir</b>, dan <b>dapat dipertanggungjawabkan</b> sebagai dasar dalam <i>perencanaan</i> serta <i>evaluasi program pembangunan</i>. \r\n      Dengan data yang baik, desa dapat menyusun kebijakan yang lebih tepat sasaran, mengalokasikan anggaran secara efektif, dan memperkuat transparansi publik. \r\n      Selain itu, data yang terbuka juga mendorong partisipasi masyarakat dalam pembangunan desa, sehingga ke depan Desa Sumurbandung dapat berkembang menjadi desa yang lebih <b>mandiri</b>, <b>berdaya saing</b>, dan berorientasi pada kebutuhan warganya.\r\n    </p>', '/assets/dokumentasi/pembinaanDClebak2.png', '2025-05-07'),
(11, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak Tahap 3: Teknik Pengolahan Data\"', '<p>Pada tanggal <b>14 Mei 2025</b>, di Desa Sumurbandung telah dilaksanakan kegiatan <i>Pembinaan Desa Cantik</i> dengan materi utama <b>Teknik Pengolahan Data</b>. \r\n      Kegiatan ini dirancang untuk membekali para peserta, khususnya perangkat desa, dengan keterampilan dalam mengolah data secara <b>sistematis</b> agar informasi yang dihasilkan akurat, relevan, dan mudah dipahami oleh berbagai pihak. \r\n      Data yang telah diolah dengan baik akan menjadi dasar penting bagi desa untuk <i>perencanaan pembangunan</i>, pelaporan kegiatan, serta evaluasi program yang sedang berjalan.</p>\r\n\r\n      <p>Dalam pembinaan ini, peserta mempelajari beberapa tahapan penting dalam pengolahan data, antara lain:</p>\r\n      <ul>\r\n        <li><b>Pembersihan Data (Data Cleaning)</b>\r\n          <ul>\r\n            <li>Menghapus data yang tidak relevan, duplikat, atau salah input agar dataset lebih rapi.</li>\r\n            <li>Memastikan tidak ada nilai kosong yang dapat mengganggu hasil analisis.</li>\r\n            <li>Proses ini sangat krusial karena kualitas data mentah akan menentukan kualitas informasi akhir.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Pengkodean Data</b>\r\n          <ul>\r\n            <li>Mengubah jawaban atau kategori kualitatif menjadi kode numerik agar lebih mudah dianalisis.</li>\r\n            <li>Mempercepat proses tabulasi dan meminimalisir kesalahan dalam pengolahan manual.</li>\r\n            <li>Memberikan struktur yang konsisten pada data sehingga lebih mudah dipahami oleh perangkat lunak analisis.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Tabulasi</b>\r\n          <ul>\r\n            <li>Mengelompokkan data dalam bentuk tabel yang terstruktur dan jelas.</li>\r\n            <li>Memudahkan perbandingan antar variabel dan mendukung analisis statistik sederhana.</li>\r\n            <li>Hasil tabulasi dapat digunakan sebagai bahan dasar untuk membuat grafik atau diagram yang lebih visual.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Penyajian Data</b>\r\n          <ul>\r\n            <li>Menggunakan tabel, grafik, dan diagram untuk menampilkan informasi dengan lebih menarik dan mudah dipahami.</li>\r\n            <li>Visualisasi yang baik membantu pembuat kebijakan maupun masyarakat umum memahami kondisi nyata desa.</li>\r\n            <li>Dengan penyajian yang jelas, data tidak hanya menjadi angka, tetapi juga menjadi cerita yang bermakna.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Selain itu, peserta juga dibimbing untuk memahami <b>standar etika</b> dalam pengolahan data, seperti menjaga kerahasiaan informasi responden dan menghindari manipulasi angka yang dapat menyesatkan. \r\n      Mereka dilatih untuk selalu bersikap <i>objektif</i> dan mengutamakan transparansi, sehingga data desa benar-benar dapat dipercaya sebagai dasar kebijakan.</p>\r\n\r\n      <p>Melalui pembinaan ini, diharapkan perangkat desa memiliki kemampuan untuk mengubah data mentah menjadi <b>informasi yang bermanfaat</b>, <b>dapat dipertanggungjawabkan</b>, dan <b>berdaya guna</b>. \r\n      Informasi tersebut tidak hanya mendukung pengambilan keputusan internal, tetapi juga menjadi bahan penting dalam <i>musyawarah desa</i>, penyusunan laporan ke pemerintah daerah, serta sarana komunikasi kepada masyarakat luas. \r\n      Dengan peningkatan kapasitas ini, Desa Sumurbandung dapat semakin <b>mandiri</b> dalam mengelola data, memperkuat akuntabilitas publik, dan memastikan setiap program pembangunan benar-benar sesuai dengan kebutuhan masyarakat.\r\n    </p>', '/assets/dokumentasi/pembinaanDClebak3.png', '2025-05-14'),
(12, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak Tahap 4: Teknik Penyimpanan Data', '<p>Pada tanggal <b>21 Mei 2025</b>, di Desa Sumurbandung telah dilaksanakan kegiatan <i>Pembinaan Desa Cantik</i> dengan materi <b>Teknik Penyimpanan Data</b>. \r\n      Kegiatan ini bertujuan untuk memberikan pemahaman yang mendalam kepada perangkat desa mengenai cara menyimpan data secara <b>terstruktur</b>, <b>aman</b>, dan <b>mudah diakses kembali</b>. \r\n      Dengan manajemen penyimpanan data yang baik, desa dapat memastikan bahwa informasi yang terkumpul tidak hanya tersimpan rapi, tetapi juga dapat dimanfaatkan untuk perencanaan, pelayanan masyarakat, serta mendukung transparansi pemerintahan desa.</p>\r\n\r\n      <p>Dalam pembinaan ini, peserta mendapatkan penjelasan tentang berbagai aspek penting penyimpanan data, meliputi:</p>\r\n      <ul>\r\n        <li><b>Penggunaan Format File yang Tepat</b>\r\n          <ul>\r\n            <li>Memahami perbedaan format file seperti <i>CSV</i>, <i>XLSX</i>, <i>PDF</i>, atau <i>DOCX</i> sesuai kebutuhan analisis maupun pelaporan.</li>\r\n            <li>Menekankan pentingnya konsistensi penggunaan format agar memudahkan integrasi dengan aplikasi lain.</li>\r\n            <li>Contoh: data penduduk disimpan dalam format tabel <i>Excel</i> untuk memudahkan tabulasi, sementara laporan kegiatan disimpan dalam <i>PDF</i> untuk menjaga keaslian dokumen.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Pengelompokan Data Berdasarkan Jenis</b>\r\n          <ul>\r\n            <li>Mengelompokkan data sesuai kategori, seperti data kependudukan, data keuangan desa, data pembangunan, dan data kegiatan sosial.</li>\r\n            <li>Pengelompokan ini mempermudah pencarian kembali ketika data diperlukan, serta menghindari tumpang tindih antar file.</li>\r\n            <li>Peserta juga diberi contoh struktur folder digital yang rapi dan terstandar.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Pembuatan Cadangan (Backup)</b>\r\n          <ul>\r\n            <li>Menjelaskan pentingnya membuat cadangan data secara berkala untuk mencegah kehilangan informasi akibat kerusakan perangkat atau bencana.</li>\r\n            <li>Peserta diperkenalkan pada konsep <i>backup ganda</i>, yaitu menyimpan salinan di perangkat lokal dan di penyimpanan eksternal/cloud.</li>\r\n            <li>Disampaikan pula strategi <i>backup otomatis</i> menggunakan layanan digital agar proses lebih efisien.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Pemanfaatan Media Penyimpanan</b>\r\n          <ul>\r\n            <li>Memahami kelebihan dan kekurangan media penyimpanan fisik (hard disk, flashdisk, arsip kertas) dan media digital (cloud storage, server lokal).</li>\r\n            <li>Ditekankan perlunya keseimbangan antara <i>keamanan</i> dan <i>kemudahan akses</i> dalam memilih media penyimpanan.</li>\r\n            <li>Contoh: data sensitif seperti laporan keuangan lebih aman disimpan di server dengan sistem proteksi, sedangkan data umum bisa dibagikan melalui cloud untuk akses cepat.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Selain aspek teknis, pembinaan ini juga menekankan pentingnya <b>keamanan data</b>. \r\n      Peserta diingatkan untuk selalu menjaga kerahasiaan informasi sensitif, menerapkan sistem sandi (password), serta memberikan hak akses terbatas hanya kepada pihak yang berwenang. \r\n      Mereka juga diperkenalkan pada praktik <i>data governance</i>, yaitu tata kelola data yang menekankan integritas, akurasi, dan keberlanjutan.</p>\r\n\r\n      <p>Melalui kegiatan ini, perangkat desa diharapkan semakin terampil dalam mengelola data, tidak hanya dari sisi pengumpulan dan pengolahan, tetapi juga dalam menjaga penyimpanan jangka panjang. \r\n      Dengan kemampuan tersebut, Desa Sumurbandung mampu memastikan bahwa setiap data yang dikumpulkan benar-benar menjadi <b>aset berharga</b> bagi pembangunan, pelayanan publik, dan peningkatan kualitas hidup masyarakat desa.\r\n    </p>', '/assets/dokumentasi/pembinaanDClebak4.png', '2025-05-21'),
(13, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak Tahap 5: Teknik Analisa Data', ' <p>Pada tanggal <b>28 Mei 2025</b>, di Desa Sumurbandung dilaksanakan kegiatan <i>Pembinaan Desa Cantik</i> dengan materi <b>Teknik Analisis Data</b>. \r\n      Kegiatan ini dirancang untuk <b>meningkatkan kemampuan perangkat desa</b> dalam mengolah dan menafsirkan data, sehingga dapat menghasilkan informasi yang <i>relevan</i> serta dapat dipertanggungjawabkan sebagai dasar perencanaan pembangunan. \r\n      Analisis data yang baik memungkinkan desa membuat keputusan yang lebih tepat, transparan, dan berbasis bukti nyata, bukan sekadar asumsi.</p>\r\n\r\n      <p>Dalam pembinaan ini, peserta mendapatkan penjelasan mendetail mengenai beberapa aspek utama, antara lain:</p>\r\n      <ul>\r\n        <li><b>Konsep Dasar Analisis Data</b>\r\n          <ul>\r\n            <li>Pengenalan istilah dasar seperti variabel, indikator, populasi, dan sampel.</li>\r\n            <li>Penjelasan mengapa analisis diperlukan untuk mengubah data mentah menjadi informasi bermakna.</li>\r\n            <li>Diberikan contoh sederhana seperti analisis pertumbuhan penduduk desa dari tahun ke tahun.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Pemilihan Metode Analisis yang Sesuai</b>\r\n          <ul>\r\n            <li>Pembahasan metode deskriptif (misalnya rata-rata, persentase, distribusi frekuensi) untuk menggambarkan kondisi nyata desa.</li>\r\n            <li>Pengenalan analisis komparatif untuk membandingkan data antar periode atau antar wilayah.</li>\r\n            <li>Pemaparan singkat tentang analisis korelasi sederhana untuk melihat hubungan antar variabel, misalnya antara tingkat pendidikan dan tingkat pendapatan masyarakat.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Membaca Pola dan Tren</b>\r\n          <ul>\r\n            <li>Peserta belajar mengenali tren dari data berkala, misalnya tren kesehatan, angka kelahiran, atau produktivitas pertanian.</li>\r\n            <li>Penjelasan mengenai pola musiman yang bisa memengaruhi data, contohnya lonjakan harga bahan pokok menjelang hari besar.</li>\r\n            <li>Pendampingan untuk membuat interpretasi yang benar, sehingga tidak salah dalam mengambil kesimpulan dari data yang tersedia.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Penyajian Hasil Analisis</b>\r\n          <ul>\r\n            <li>Hasil analisis tidak hanya disampaikan dalam bentuk angka, tetapi juga dalam visualisasi seperti tabel, grafik, dan diagram.</li>\r\n            <li>Ditekankan pentingnya menyajikan data dalam format yang <i>mudah dipahami</i> oleh perangkat desa maupun masyarakat umum.</li>\r\n            <li>Contoh: tren kependudukan divisualkan dalam grafik garis, sementara perbandingan sektor ekonomi dapat ditampilkan dalam diagram batang.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Pembinaan ini juga menekankan pentingnya <b>ketelitian</b> dalam membaca hasil analisis, karena kesalahan kecil dapat berakibat pada pengambilan keputusan yang tidak tepat. \r\n      Selain itu, peserta didorong untuk selalu melakukan <i>cross-check</i> atau validasi data agar informasi yang dihasilkan benar-benar akurat dan dapat dipertanggungjawabkan.</p>\r\n\r\n      <p>Melalui kegiatan ini, diharapkan perangkat desa semakin terampil dalam mengubah data mentah menjadi informasi yang bermanfaat. \r\n      Dengan bekal analisis yang baik, Desa Sumurbandung dapat merancang program pembangunan yang lebih <b>tepat sasaran</b>, <b>efektif</b>, serta memberikan dampak nyata bagi kesejahteraan masyarakat.\r\n    </p>', '/assets/dokumentasi/pembinaanDClebak5.png', '2025-05-28'),
(14, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak Tahap 6: Teknik Penyajian Data', '<p>Pada tanggal <b>4 Juni 2025</b>, di Desa Sumurbandung dilaksanakan kegiatan <i>Pembinaan Desa Cantik</i> dengan materi <b>Teknik Penyajian Data</b>. \r\n      Kegiatan ini bertujuan membekali perangkat desa dengan keterampilan praktis dalam menyajikan data agar informasi yang dihasilkan <b>jelas</b>, <b>menarik</b>, dan <b>mudah dipahami</b> oleh berbagai pihak. \r\n      Penyajian data yang tepat tidak hanya meningkatkan pemahaman masyarakat, tetapi juga memperkuat <i>transparansi</i> dan <i>akuntabilitas</i> desa dalam mengelola informasi pembangunan.</p>\r\n\r\n      <p>Dalam kegiatan pembinaan, peserta memperoleh penjelasan tentang berbagai aspek penting, antara lain:</p>\r\n      <ul>\r\n        <li><b>Prinsip-prinsip Penyajian Data</b>\r\n          <ul>\r\n            <li>Pentingnya menampilkan data secara <i>sederhana</i> namun tetap informatif.</li>\r\n            <li>Peserta didorong untuk menghindari penggunaan angka yang terlalu rumit tanpa penjelasan tambahan.</li>\r\n            <li>Diberikan contoh penyajian data kependudukan yang ringkas, tetapi tetap menunjukkan tren dan distribusi dengan jelas.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Pemilihan Bentuk Visualisasi yang Tepat</b>\r\n          <ul>\r\n            <li><b>Tabel</b> untuk menyajikan detail angka yang presisi, seperti jumlah penduduk per dusun.</li>\r\n            <li><b>Grafik</b> untuk memperlihatkan tren perkembangan, misalnya peningkatan produksi pertanian dari tahun ke tahun.</li>\r\n            <li><b>Diagram</b> lingkaran untuk menggambarkan proporsi, seperti persentase mata pencaharian warga.</li>\r\n            <li><b>Peta</b> tematik untuk menunjukkan sebaran fasilitas umum, potensi wilayah, atau tingkat partisipasi program desa.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Penggunaan Warna dan Tata Letak</b>\r\n          <ul>\r\n            <li>Ditekankan pentingnya konsistensi warna agar tidak membingungkan pembaca.</li>\r\n            <li>Pemilihan palet warna yang ramah mata, dengan kombinasi kontras untuk menonjolkan informasi utama.</li>\r\n            <li>Tata letak yang rapi dan seimbang membantu pembaca lebih cepat menangkap pesan yang ingin disampaikan.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Keterampilan Komunikasi Visual</b>\r\n          <ul>\r\n            <li>Peserta dilatih untuk menyampaikan data dengan narasi singkat yang mendukung visualisasi.</li>\r\n            <li>Penekanan pada pentingnya <i>storytelling dengan data</i>, sehingga angka tidak hanya berdiri sendiri tetapi membentuk cerita yang bermakna.</li>\r\n            <li>Simulasi penyajian data dilakukan agar peserta terbiasa berbicara di depan audiens dengan percaya diri.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Melalui pembinaan ini, perangkat desa diharapkan mampu menyajikan hasil pengolahan data secara <b>informatif</b> dan <b>komunikatif</b>. \r\n      Data yang ditampilkan dengan visualisasi yang baik akan memperkuat kepercayaan masyarakat, mendukung <i>pengambilan keputusan berbasis data</i>, serta menjadi sarana evaluasi program pembangunan desa. \r\n      Dengan begitu, Desa Sumurbandung dapat semakin maju, mandiri, dan akuntabel dalam pengelolaan informasi pembangunan.\r\n    </p>', '/assets/dokumentasi/pembinaanDClebak6.png', '2025-06-04'),
(15, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak Tahap 7: Manajemen Kualitas Data', '<p>Pada tanggal <b>11 Juni 2025</b>, di Desa Sumurbandung dilaksanakan kegiatan <i>Pembinaan Desa Cantik</i> dengan materi <b>Manajemen Kualitas Data</b>. \r\n      Kegiatan ini bertujuan meningkatkan pemahaman perangkat desa mengenai pentingnya menjaga mutu data agar <b>akurat</b>, <b>konsisten</b>, <b>lengkap</b>, dan <b>tepat waktu</b>. \r\n      Mutu data yang terjamin tidak hanya bermanfaat bagi desa itu sendiri, tetapi juga mendukung pembangunan yang berkelanjutan dan berbasis bukti di tingkat kabupaten maupun provinsi.</p>\r\n\r\n      <p>Dalam pembinaan ini, peserta mendapatkan penjelasan mengenai berbagai aspek penting, antara lain:</p>\r\n      <ul>\r\n        <li><b>Prinsip-prinsip Kualitas Data</b>\r\n          <ul>\r\n            <li><b>Akurasi</b>: memastikan data yang dicatat sesuai dengan kondisi sebenarnya.</li>\r\n            <li><b>Konsistensi</b>: menjaga keseragaman format dan metode pencatatan antar periode.</li>\r\n            <li><b>Kelengkapan</b>: memastikan seluruh variabel dan indikator yang diperlukan tersedia.</li>\r\n            <li><b>Ketepatan waktu</b>: data dikumpulkan dan dipublikasikan sesuai jadwal sehingga relevan dengan kebutuhan.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Deteksi dan Perbaikan Kesalahan Data</b>\r\n          <ul>\r\n            <li>Mempelajari teknik <i>data validation</i> untuk menemukan entri yang tidak logis.</li>\r\n            <li>Melakukan pengecekan silang antara sumber data berbeda, misalnya data kependudukan dan data pelayanan kesehatan.</li>\r\n            <li>Menggunakan metode koreksi manual dan digital untuk memperbaiki kesalahan pencatatan.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Langkah-langkah Pengendalian Kualitas</b>\r\n          <ul>\r\n            <li>Pada tahap <b>pengumpulan</b>: memastikan instrumen sudah diuji coba dan enumerator terlatih.</li>\r\n            <li>Pada tahap <b>pengolahan</b>: melakukan proses <i>data cleaning</i> agar data siap dianalisis.</li>\r\n            <li>Pada tahap <b>penyajian</b>: memastikan tabel, grafik, dan infografis tidak menimbulkan bias interpretasi.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Melalui pembinaan ini, perangkat desa diharapkan mampu menghasilkan data yang <b>dapat dipercaya</b> dan <b>dapat dipertanggungjawabkan</b>. \r\n      Data yang berkualitas akan menjadi dasar bagi <i>perencanaan pembangunan</i>, <i>evaluasi program</i>, serta pengambilan keputusan yang lebih tepat sasaran. \r\n      Dengan demikian, Desa Sumurbandung dapat membangun sistem informasi desa yang lebih profesional dan berdaya guna bagi masyarakat.\r\n    </p>', '/assets/dokumentasi/pembinaanDClebak7.png', '2025-06-11'),
(16, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Lebak Tahap 8: Finalisasi', '<p>Pada tanggal <b>18 Juni 2025</b>, di Desa Sumurbandung dilaksanakan <i>Pembinaan Desa Cantik</i> tahap <b>Finalisasi</b>. \r\n      Kegiatan ini menjadi penutup rangkaian pembinaan tahun 2025 yang sebelumnya telah mencakup berbagai materi penting, mulai dari <i>identifikasi kebutuhan data</i>, \r\n      <i>teknik pengumpulan</i>, <i>pengolahan</i>, <i>penyimpanan</i>, <i>analisis</i>, <i>penyajian</i>, hingga <i>manajemen kualitas data</i>. \r\n      Tahap finalisasi ini berperan sebagai momen refleksi untuk mengukur sejauh mana perangkat desa mampu memahami, menerapkan, dan mengintegrasikan seluruh materi yang telah dipelajari.</p>\r\n\r\n      <p>Pada sesi finalisasi, peserta melakukan beberapa aktivitas kunci, antara lain:</p>\r\n      <ul>\r\n        <li><b>Evaluasi Hasil Pembinaan</b>\r\n          <ul>\r\n            <li>Meninjau kembali catatan pembelajaran dari tiap pertemuan.</li>\r\n            <li>Mendiskusikan kesulitan yang dialami selama praktik lapangan.</li>\r\n            <li>Mengevaluasi peningkatan keterampilan perangkat desa dalam mengelola data.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Pemeriksaan Data yang Dihimpun</b>\r\n          <ul>\r\n            <li>Mengecek kelengkapan variabel yang sudah dikumpulkan.</li>\r\n            <li>Melakukan uji konsistensi antar dokumen dan antar periode waktu.</li>\r\n            <li>Memastikan keterpaduan informasi antar bidang, misalnya data kependudukan, ekonomi, dan kesehatan.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Finalisasi Sistem Pengelolaan Data</b>\r\n          <ul>\r\n            <li>Menyusun format standar untuk laporan dan publikasi data desa.</li>\r\n            <li>Membuat cadangan (<i>backup</i>) data untuk menjaga keamanan dan keberlanjutan.</li>\r\n            <li>Menerapkan prinsip transparansi agar data dapat dimanfaatkan masyarakat secara luas.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Melalui tahap <b>finalisasi</b> ini, Desa Sumurbandung diharapkan benar-benar siap dengan sistem pengelolaan data yang <b>terstruktur</b>, <b>terintegrasi</b>, \r\n      dan <b>dapat dipertanggungjawabkan</b>. Data yang telah dihimpun akan menjadi dasar bagi <i>perencanaan pembangunan desa</i> yang lebih tepat sasaran, \r\n      serta menjadi alat penting untuk meningkatkan <b>transparansi</b>, <b>akuntabilitas</b>, dan <b>partisipasi masyarakat</b> dalam pembangunan berkelanjutan.\r\n    </p>', '/assets/dokumentasi/pembinaanDClebak8.png', '2025-06-18');
INSERT INTO `tb_dokumentasi` (`id`, `title`, `desk`, `img`, `date`) VALUES
(17, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Tangerang', '<p>Kegiatan <b>pembinaan literasi statistik</b> bertema <i>Generic Statistical Business Process Model (GSBPM)</i> dan \r\n      <b>manajemen data</b> dilaksanakan di Aula Desa Sukawali. Acara ini dihadiri lengkap oleh <b>aparat desa</b>, \r\n      <b>agen statistik</b>, <b>mahasiswa magang</b>, serta <b>perwakilan warga</b>, sehingga tingkat partisipasi \r\n      mencapai <b>100%</b>. Kehadiran semua unsur masyarakat desa menunjukkan tingginya antusiasme terhadap pentingnya \r\n      pengelolaan data dan komitmen bersama dalam mewujudkan tata kelola desa berbasis data.</p>\r\n\r\n      <p>Rangkaian kegiatan berlangsung sebagai berikut:</p>\r\n      <ul>\r\n        <li><b>Pembukaan</b>\r\n          <ul>\r\n            <li>Acara dibuka oleh <b>Kepala Desa Sukawali</b> yang menekankan urgensi literasi statistik \r\n            bagi desa sebagai dasar pengambilan keputusan berbasis data.</li>\r\n            <li>Sambutan dilanjutkan oleh <b>Kepala BPS Kabupaten Tangerang</b> yang menegaskan pentingnya \r\n            penerapan <i>GSBPM</i> dan manajemen data dalam pembangunan desa.</li>\r\n            <li>Beliau juga menyampaikan apresiasi atas dukungan penuh perangkat desa dalam menyukseskan kegiatan ini.</li>\r\n          </ul>\r\n        </li>\r\n        \r\n        <li><b>Penyampaian Materi Inti</b>\r\n          <ul>\r\n            <li>Dibawakan oleh <b>Pembina Desa Cantik BPS Kabupaten Tangerang</b>.</li>\r\n            <li>Materi yang dipaparkan meliputi:\r\n              <ul>\r\n                <li><b>Regulasi Sistem Statistik Nasional (SSN)</b> sebagai landasan hukum penyelenggaraan statistik.</li>\r\n                <li><b>Konsep kegiatan statistik</b> yang mencakup tahapan penyusunan hingga pemanfaatan data.</li>\r\n                <li><i>Generic Statistical Business Process Model (GSBPM)</i> dengan <b>delapan tahapan siklus statistik</b>\r\n                mulai dari identifikasi kebutuhan, perancangan, pengumpulan, pengolahan, analisis, hingga diseminasi.</li>\r\n                <li>Prinsip <i>Satu Data Indonesia</i> yang menekankan <b>standar data</b>, <b>metadata</b>, \r\n                <b>interoperabilitas</b>, dan pemanfaatan <b>data induk</b> secara konsisten.</li>\r\n              </ul>\r\n            </li>\r\n          </ul>\r\n        </li>\r\n        \r\n        <li><b>Sesi Diskusi</b>\r\n          <ul>\r\n            <li>Peserta mengajukan pertanyaan seputar:\r\n              <ul>\r\n                <li>Relevansi standardisasi data di tingkat desa.</li>\r\n                <li>Manfaat praktis <i>GSBPM</i> dalam kegiatan statistik sehari-hari.</li>\r\n                <li>Kesiapan desa tanpa latar belakang statistik dalam menerapkan konsep ini.</li>\r\n                <li>Tahapan penyusunan metadata yang sesuai standar.</li>\r\n                <li>Penerapan interoperabilitas dan <i>standar data</i> agar terhubung dengan sistem kabupaten hingga pusat.</li>\r\n              </ul>\r\n            </li>\r\n            <li>Narasumber menegaskan bahwa:\r\n              <ul>\r\n                <li><b>Standar data</b> dan <i>GSBPM</i> justru mempermudah desa mengelola informasi agar konsisten dan akurat.</li>\r\n                <li>Penerapan standar membuat data desa <b>dapat dibandingkan</b> dengan kabupaten, provinsi, hingga nasional.</li>\r\n                <li>Dengan sistem yang terintegrasi, proses pelaporan menjadi lebih efisien dan mengurangi risiko duplikasi.</li>\r\n              </ul>\r\n            </li>\r\n          </ul>\r\n        </li>\r\n        \r\n        <li><b>Manfaat Nyata Bagi Desa</b>\r\n          <ul>\r\n            <li>Mempercepat penyusunan usulan program pembangunan desa.</li>\r\n            <li>Meningkatkan kepercayaan pemerintah pusat terhadap data yang disampaikan desa.</li>\r\n            <li>Menghindari tumpang tindih atau inkonsistensi data antar lembaga.</li>\r\n            <li>Mendorong kebijakan berbasis bukti (<i>evidence-based policy</i>) yang lebih tepat sasaran.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Dengan demikian, Program <b>Desa Cantik</b> tidak hanya memperkuat kapasitas aparat desa sebagai <i>produsen data</i>, \r\n      tetapi juga meneguhkan peran desa dalam mendukung <b>Sistem Statistik Nasional (SSN)</b> dan mewujudkan <b>Satu Data Indonesia</b>. \r\n      Kegiatan ini menjadi tonggak penting agar Desa Sukawali mampu menjadi contoh penerapan literasi statistik di tingkat lokal, \r\n      serta memperlihatkan bahwa desa memiliki kontribusi besar dalam pembangunan berbasis data.\r\n    </p>', '/assets/dokumentasi/pembinaanDCtangerang.png', '2025-05-02'),
(18, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Serang: Identifikasi Kebutuhan Desa', '<p><b>Rapat Sosialisasi Program Desa Cantik</b> antara <b>BPS Kabupaten Serang</b> dan <b>Pemerintah Desa Cikande Permai</b> \r\n      dilaksanakan pada <b>30 April 2025</b> di kantor desa. Rapat dipimpin langsung oleh <b>Kepala Desa Cikande Permai</b>, \r\n      menunjukkan keseriusan pemerintah desa dalam mendukung peningkatan literasi statistik. Kegiatan ini dihadiri oleh perangkat desa, \r\n      mahasiswa magang, dan perwakilan masyarakat sehingga suasana rapat berjalan aktif dan partisipatif.</p>\r\n\r\n      <p><b>Materi pembinaan</b> disampaikan oleh <b>Novian Tamara</b> dengan mengacu pada panduan resmi BPS. \r\n      Peserta diperkenalkan pada sejumlah pokok bahasan penting, di antaranya:</p>\r\n\r\n      <ul>\r\n        <li><b>Penjelasan umum tentang Desa Cantik</b>\r\n          <ul>\r\n            <li>Program sebagai upaya <i>peningkatan literasi statistik</i> di tingkat desa.</li>\r\n            <li>Pentingnya tata kelola data yang sistematis untuk pembangunan berbasis bukti.</li>\r\n            <li>Skema pendampingan dari BPS kepada desa mitra.</li>\r\n          </ul>\r\n        </li>\r\n\r\n        <li><b>Tujuan program</b>\r\n          <ul>\r\n            <li>Standardisasi <b>pengelolaan data desa</b> agar lebih konsisten dan terpercaya.</li>\r\n            <li>Pembentukan <b>agen statistik</b> sebagai penggerak literasi di tingkat lokal.</li>\r\n            <li>Optimalisasi pemanfaatan data dalam <b>perencanaan pembangunan desa</b>.</li>\r\n          </ul>\r\n        </li>\r\n\r\n        <li><b>Tahapan pembinaan</b>\r\n          <ul>\r\n            <li>Sosialisasi dan pengenalan program.</li>\r\n            <li>Identifikasi potensi dan kebutuhan desa melalui <i>instrumen kuesioner</i>.</li>\r\n            <li>Penyusunan rencana kegiatan yang berbasis data.</li>\r\n            <li>Pelaksanaan kegiatan secara bertahap.</li>\r\n            <li>Monitoring serta evaluasi hasil pembinaan untuk menjamin keberlanjutan.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p><b>Diskusi</b> berlangsung interaktif, dengan beberapa hal yang mengemuka:</p>\r\n      <ul>\r\n        <li>Peserta menanyakan bentuk nyata <b>output program Desa Cantik</b> di desa mereka.</li>\r\n        <li>Mahasiswa magang menunjukkan <b>minat terlibat langsung</b> dalam kegiatan statistik desa.</li>\r\n        <li>Kepala Desa menyatakan <b>komitmen resmi</b> menunjuk agen statistik dan mendukung pembinaan berkelanjutan.</li>\r\n      </ul>\r\n\r\n      <p><b>Hasil identifikasi kebutuhan Desa Cikande Permai</b> menargetkan beberapa kegiatan strategis, antara lain:</p>\r\n      <ul>\r\n        <li>Pengembangan <b>website/dashboard statistik</b> berbasis platform <i>DIGIDES</i>.</li>\r\n        <li>Pembuatan <b>infografis</b> yang menarik dan mudah dipahami.</li>\r\n        <li>Pelaksanaan <b>survei kepuasan</b> masyarakat terhadap layanan infrastruktur dan kinerja pemerintah desa.</li>\r\n        <li>Penerbitan <b>lima publikasi statistik</b>, meliputi:\r\n          <ul>\r\n            <li>Profil desa.</li>\r\n            <li>Buku saku data strategis.</li>\r\n            <li>Analisis survei kepuasan masyarakat.</li>\r\n            <li><i>Desa dalam Angka</i>.</li>\r\n            <li>Booklet potensi desa.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p>Acara ditutup dengan semangat kolaborasi antara <b>pembina, perangkat desa, mahasiswa, dan masyarakat</b>. \r\n      Momentum ini meneguhkan tekad bersama untuk menjadikan Desa Cikande Permai sebagai desa percontohan dalam pengelolaan data. \r\n      Sosialisasi ditutup dengan seruan penuh semangat: <i><b>“DESA HEBAT, STATISTIK TEPAT!”</b></i>\r\n    </p>', '/assets/dokumentasi/pembinaanDCserang1.png', '2025-04-30'),
(19, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kab. Serang: Briefing Petugas Survei Kepuasan Layanan Infrastruktur', '<p><b>Pelatihan dan briefing Survei Kepuasan Layanan Infrastruktur dan Kinerja Pemerintah Desa Cikande Permai 2025</b> \r\n      dilaksanakan pada <b>23 Mei 2025</b> di Kantor Desa Cikande Permai. Acara ini dipimpin langsung oleh <b>Kepala Desa Dayari</b> \r\n      dan diikuti oleh <b>agen statistik</b>, <b>tim pembina BPS Kabupaten Serang</b>, serta <b>mahasiswa magang Unpam Serang</b>. \r\n      Kehadiran peserta yang lengkap mencerminkan komitmen desa untuk melaksanakan survei ini dengan serius dan terarah.</p>\r\n\r\n      <p><b>Topik utama yang dibahas</b> dalam kegiatan ini meliputi:</p>\r\n      <ul>\r\n        <li>Pentingnya <b>data statistik</b> sebagai dasar pembangunan desa yang berbasis bukti.</li>\r\n        <li><b>Tujuan survei</b>, yaitu menilai tingkat kepuasan masyarakat terhadap:\r\n          <ul>\r\n            <li><b>Layanan infrastruktur</b> yang tersedia di desa.</li>\r\n            <li><b>Kinerja pemerintah desa</b> dalam memberikan pelayanan publik.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Penerapan kerangka kerja <i>Generic Statistical Business Process Model (GSBPM)</i> sebagai acuan standar pelaksanaan survei.</li>\r\n      </ul>\r\n\r\n      <p><b>Desain survei</b> disusun secara rinci agar hasilnya valid dan representatif, mencakup:</p>\r\n      <ul>\r\n        <li>Metode pengumpulan data menggunakan <b>wawancara langsung</b> dengan kuesioner standar.</li>\r\n        <li>Cakupan wilayah seluruh <b>9 RW</b> di Desa Cikande Permai.</li>\r\n        <li>Responden adalah <b>rumah tangga terpilih</b> yang mewakili populasi desa.</li>\r\n      </ul>\r\n\r\n      <p><b>Pelatihan petugas lapangan</b> dipandu oleh <b>Novian Tamara</b> bersama <b>Maman</b>, meliputi:</p>\r\n      <ul>\r\n        <li>Pemaparan materi secara teori tentang prosedur pencacahan.</li>\r\n        <li>Simulasi wawancara langsung untuk melatih keterampilan komunikasi.</li>\r\n        <li>Penilaian kelulusan oleh <b>Kepala Desa</b> sebagai bentuk verifikasi kesiapan petugas.</li>\r\n        <li>Petugas yang dinyatakan lulus diberikan <b>ID Card</b> dan <b>surat tugas resmi</b> sebagai tanda legalitas.</li>\r\n      </ul>\r\n\r\n      <p><b>Rapat juga menetapkan timeline kegiatan</b> dari <b>22 Mei hingga 1 Juli 2025</b>, dengan tahapan:</p>\r\n      <ul>\r\n        <li>Pelatihan petugas.</li>\r\n        <li>Pencacahan lapangan di seluruh wilayah sasaran.</li>\r\n        <li>Pengawasan lapangan untuk menjamin kualitas data.</li>\r\n        <li>Entri data dan proses <i>data cleaning</i>.</li>\r\n        <li>Analisis hasil survei.</li>\r\n        <li>Publikasi hasil survei untuk disampaikan kepada masyarakat dan pemangku kepentingan.</li>\r\n      </ul>\r\n\r\n      <p><b>Tugas dan tanggung jawab</b> dijabarkan secara jelas, meliputi:</p>\r\n      <ul>\r\n        <li><b>Pencacah</b> bertugas melakukan wawancara langsung kepada responden dengan penuh etika dan objektivitas.</li>\r\n        <li><b>Pengawas</b> bertugas memastikan kualitas data tetap terjaga, memberikan bimbingan, serta melakukan pemeriksaan lapangan.</li>\r\n      </ul>\r\n\r\n      <p><b>Distribusi logistik</b> juga dilakukan, mencakup:\r\n      <ul>\r\n        <li>Kuesioner standar.</li>\r\n        <li>Alat tulis.</li>\r\n        <li>ID Card petugas.</li>\r\n        <li>Surat tugas resmi.</li>\r\n        <li>Daftar sampel responden.</li>\r\n      </ul>\r\n      Seluruh logistik dikelola secara transparan agar pelaksanaan survei berjalan lancar.</p>\r\n\r\n      <p>Penting untuk dicatat bahwa <b>seluruh biaya survei ditanggung oleh Pemerintah Desa</b>, \r\n      dengan pengawasan langsung dari <b>tim PDCS BPS Kabupaten Serang</b> demi menjaga kualitas dan akuntabilitas. \r\n      Acara ditutup dengan pesan penting agar petugas selalu menjunjung tinggi <b>etika, profesionalitas, dan objektivitas</b> dalam setiap tahap kegiatan.</p>\r\n\r\n      <p>Dengan semangat kebersamaan, peserta meyakini bahwa hasil survei ini akan memberikan <b>manfaat nyata</b> bagi pembangunan desa, \r\n      serta memperkuat arah kebijakan yang berbasis data. Penutup rapat ditandai dengan seruan penuh semangat: \r\n      <i><b>“DESA HEBAT, STATISTIK TEPAT!”</b></i>\r\n    </p>', '/assets/dokumentasi/pembinaanDCserang2.png', '2025-05-23'),
(20, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Lanjutan Kab. Serang: Pengecekan Progress Pembuatan Publikasi Statistik', ' <p><b>Pembinaan lanjutan Program Desa Cinta Statistik (Desa Cantik)</b> di Desa Cikande Permai \r\n      dilaksanakan pada <b>26 Juni 2025</b> dan dipimpin oleh <b>Kepala Desa Dayari</b>. \r\n      Fokus utama kegiatan ini adalah <b>evaluasi progres penyusunan publikasi statistik desa</b> yang menjadi target bersama.</p>\r\n\r\n      <p><b>Narasumber dari BPS Kabupaten Serang</b> menyampaikan materi teknis secara komprehensif, meliputi:</p>\r\n      <ul>\r\n        <li>Pengumpulan dan pengolahan data desa.</li>\r\n        <li>Analisis deskriptif untuk penyajian informasi.</li>\r\n        <li>Tata kelola data dan sistem informasi.</li>\r\n        <li>Penyajian serta diseminasi hasil publikasi.</li>\r\n        <li>Pentingnya <b>metadata</b> sebagai pelengkap setiap publikasi.</li>\r\n      </ul>\r\n\r\n      <p><b>Pembina Desa Cantik</b> menekankan hal-hal penting berikut:</p>\r\n      <ul>\r\n        <li>Percepatan penyusunan lima publikasi desa yang telah direncanakan.</li>\r\n        <li>Pentingnya koordinasi lintas penanggung jawab agar pekerjaan lebih terarah.</li>\r\n        <li>Konsistensi data agar informasi yang dihasilkan <b>kredibel, akurat, dan bermanfaat</b> untuk perencanaan pembangunan desa.</li>\r\n      </ul>\r\n\r\n      <p><b>Agen statistik desa</b> turut menyampaikan beberapa kendala yang dihadapi, antara lain:</p>\r\n      <ul>\r\n        <li>Keterbatasan kemampuan teknis dalam pengolahan data.</li>\r\n        <li>Waktu yang terbagi karena persiapan peringatan <b>HUT Desa</b>.</li>\r\n        <li>Koordinasi antar tim yang masih belum optimal.</li>\r\n      </ul>\r\n\r\n      <p><b>Lima publikasi desa yang sedang disusun</b> adalah:</p>\r\n      <ul>\r\n        <li><b>Buku Profil Desa</b></li>\r\n        <li><b>Buku Saku Data Strategis</b></li>\r\n        <li><b>Analisis Survei Kepuasan Layanan Infrastruktur dan Kinerja Pemerintah Desa</b></li>\r\n        <li><b>Desa Dalam Angka</b></li>\r\n        <li><b>Booklet Potensi Desa</b></li>\r\n      </ul>\r\n\r\n      <p><b>Rencana tindak lanjut</b> yang disepakati mencakup:</p>\r\n      <ul>\r\n        <li>Penyusunan <b>jadwal percepatan</b> penyelesaian publikasi.</li>\r\n        <li>Pendampingan teknis berkelanjutan oleh tim <b>BPS Kabupaten Serang</b>.</li>\r\n        <li>Pembentukan <b>grup koordinasi lintas publikasi</b> untuk memperlancar komunikasi.</li>\r\n        <li>Pelaksanaan <b>review internal</b> sebelum publikasi resmi diterbitkan.</li>\r\n      </ul>\r\n\r\n      <p>Kegiatan pembinaan ini ditutup dengan <b>komitmen bersama</b> untuk menyelesaikan seluruh publikasi \r\n      secara tepat waktu dan berkualitas, sebagai langkah nyata menguatkan budaya statistik di tingkat desa. \r\n      Acara ditutup dengan semangat penuh optimisme melalui slogan: \r\n      <i><b>“DESA HEBAT, STATISTIK TEPAT!”</b></i>\r\n    </p>', '/assets/dokumentasi/pembinaanDCserang3.png', '2025-06-26'),
(21, 'Evaluasi Akhir Program Desa Cinta Statistik (DesaCantik) Kab. Serang: Ekpos Data Desa Cinta Statistik Cikande Permai', ' <p><b>Ekspose Data Desa Cantik Cikande Permai</b> diselenggarakan pada <b>31 Juli 2025</b> di Kantor Desa Cikande Permai, \r\n      dipimpin langsung oleh <b>Kepala Desa</b> dan dihadiri oleh <b>Camat Mochamad Agus</b>, \r\n      tim <b>BPS Kabupaten Serang</b>, serta seluruh perangkat desa. \r\n      Acara ini menjadi momen penting untuk menampilkan hasil pembinaan Program Desa Cantik selama tiga bulan terakhir.</p>\r\n\r\n      <p>Dalam sambutannya, <b>Camat Mochamad Agus</b> menyampaikan apresiasi dan harapan agar Desa Cikande Permai \r\n      dapat meraih prestasi hingga ke tingkat nasional melalui penguatan literasi statistik. \r\n      Sementara itu, <b>Novian Tamara</b> menegaskan bahwa melalui pembinaan intensif, \r\n      desa berhasil meningkatkan kapasitas aparatur dalam bidang statistik dengan capaian yang sangat membanggakan.</p>\r\n\r\n      <p><b>Beberapa capaian utama yang dipaparkan meliputi:</b></p>\r\n      <ul>\r\n        <li>Pembentukan <b>17 agen statistik desa</b>—jumlah terbanyak di Provinsi Banten—yang kini mampu menyusun publikasi, membuat infografis, dan melaksanakan survei secara mandiri.</li>\r\n        <li>Pelaksanaan <b>Survei Kepuasan Layanan Infrastruktur</b> yang menghasilkan indeks <b>85,15</b> dan \r\n            <b>Indeks Kinerja Pemerintah Desa</b> dengan capaian <b>85,65</b>, keduanya menunjukkan tingkat kepuasan masyarakat yang sangat tinggi.</li>\r\n        <li>Peluncuran <b>dua website penyajian data</b>, yaitu <b>website Digides</b> dan <b>website Desa Cantik</b>, \r\n            yang dapat diakses masyarakat dengan fitur informatif dan cukup lengkap.</li>\r\n      </ul>\r\n\r\n      <p><b>Asep Suryana</b> menambahkan bahwa keberhasilan ini mencerminkan kesiapan Desa Cikande Permai dalam mengelola, \r\n      menyajikan, dan mendiseminasikan data secara profesional. Dengan capaian tersebut, \r\n      desa tidak hanya memperkuat kapasitas aparatur dan masyarakat dalam literasi statistik, \r\n      tetapi juga menegaskan posisinya sebagai <b>desa percontohan statistik di Kabupaten Serang</b>.</p>\r\n\r\n      <p>Melalui ekspose ini, Desa Cikande Permai meneguhkan komitmennya untuk terus mendukung pembangunan berbasis data, \r\n      serta mengimplementasikan semangat <i><b>“DESA HEBAT, STATISTIK TEPAT!”</b></i> sebagai pilar utama perencanaan desa yang modern dan berdaya saing.\r\n    </p>\r\n    `,\r\n    img: \"/assets/dokumentasi/pembinaanDCserang4.png\", \r\n    date: \"31 Juli 2025\" \r\n  },\r\n  foto22: { \r\n    title: \"Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Tahap 1: Sosialisasi Desa Cinta Statistik 2025\", \r\n    desc: `\r\n    <p><b>Sosialisasi Program Desa Cantik 2025</b> oleh <b>Tim Pembina Desa Cantik Provinsi Banten</b> \r\n      dilaksanakan pada <b>Jumat, 2 Mei 2025</b> melalui <i>Zoom Meeting</i> dengan melibatkan peserta dari \r\n      <b>BPS Kota Tangerang</b>, tim pelaksana Desa Cantik, serta perwakilan agen statistik dari kelurahan \r\n      penerima program Desa Cantik tahun 2021–2025. Kegiatan ini menjadi sarana penting untuk menyamakan \r\n      pemahaman sekaligus memperkuat komitmen seluruh pihak yang terlibat dalam implementasi program.</p>\r\n\r\n      <p>Dalam paparannya, <b>Ketua Tim Desa Cantik</b> menjelaskan bahwa program ini memiliki landasan hukum dan \r\n      arah kebijakan yang jelas, yakni <i>UU Statistik</i>, <i>Perpres Satu Data Indonesia</i>, \r\n      <i>Roadmap Reformasi Birokrasi</i>, serta <i>UU Desa</i>. Program Desa Cantik menempatkan desa atau \r\n      kelurahan sebagai <b>subjek pembangunan</b> dengan tujuan meningkatkan literasi statistik, \r\n      menstandarisasi pengelolaan data, mengoptimalkan pemanfaatan data pembangunan, serta membentuk \r\n      <b>agen statistik</b> yang berperan sebagai motor penggerak pengelolaan data di tingkat desa/kelurahan.</p>\r\n\r\n      <p><b>Output pembinaan</b> yang diharapkan dari program ini antara lain:</p>\r\n      <ul>\r\n        <li>Terbangunnya <b>pengelolaan statistik desa/kelurahan</b> yang terstruktur dan berkelanjutan.</li>\r\n        <li>Terbentuknya <b>agen statistik</b> desa/kelurahan yang berkompeten.</li>\r\n        <li>Penerbitan <b>piagam penghargaan</b> bagi desa/kelurahan yang berhasil.</li>\r\n        <li>Publikasi statistik berupa <i>monografi/profil desa</i>, <i>publikasi tematik</i>, hingga <b>website resmi</b> sebagai media diseminasi data.</li>\r\n        <li>Adanya <b>pemilihan Desa Cantik terbaik</b> sebagai bentuk apresiasi atas kinerja dan inovasi.</li>\r\n      </ul>\r\n\r\n      <p>Sementara itu, <b>kriteria pemilihan desa/kelurahan Cantik</b> meliputi: \r\n      belum pernah diajukan sebelumnya, memiliki lokasi yang relatif dekat dengan kantor BPS setempat, \r\n      tersedianya fasilitas internet dan perangkat komputer yang memadai, serta aparat desa/kelurahan \r\n      yang mampu mengoperasikan teknologi tersebut. Hal ini dipandang penting agar program dapat berjalan efektif \r\n      dan memberikan hasil nyata di lapangan.</p>\r\n\r\n      <p>Melalui sosialisasi ini, diharapkan seluruh peserta memperoleh pemahaman menyeluruh mengenai \r\n      arah kebijakan, tujuan, serta tahapan pelaksanaan Desa Cantik. Lebih jauh lagi, program ini diharapkan \r\n      dapat <b>memperkuat kapasitas desa/kelurahan</b> dalam mengelola dan memanfaatkan data sebagai dasar \r\n      pembangunan yang lebih tepat sasaran, berkelanjutan, dan selaras dengan semangat \r\n      <i><b>Satu Data Indonesia</b></i>.\r\n    </p>', '/assets/dokumentasi/pembinaanDCserang4.png', '2025-07-31'),
(22, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Tahap 2: Pencanangan Desa Cantik Tahun 2025 sekaligus Pembinaan Desa Cantik', ' <p><b>Pencanangan Desa Cantik Tahun 2025</b> sekaligus <b>Pembinaan Kelurahan Pabuaran</b> \r\n      dilaksanakan pada <b>Selasa, 6 Mei 2025</b> di Aula Kelurahan Pabuaran. \r\n      Acara ini dihadiri oleh <b>BPS Kota Tangerang</b>, <b>Bappeda</b>, <b>Diskominfo</b>, <b>Camat Karawaci</b>, \r\n      <b>Lurah Pabuaran</b>, Tim Desa Cantik, agen statistik, serta para ketua RW.</p>\r\n\r\n      <p><b>Kepala BPS Kota Tangerang</b> menegaskan tujuan utama program Desa Cantik, yaitu:</p>\r\n      <ul>\r\n        <li>Meningkatkan <b>literasi statistik</b> aparat kelurahan.</li>\r\n        <li>Memperkuat kemampuan pemanfaatan data sebagai dasar perencanaan dan pengambilan keputusan.</li>\r\n      </ul>\r\n\r\n      <p><b>Kelurahan Pabuaran</b> ditetapkan sebagai <b>Kelurahan Cantik 2025</b> dengan tiga agen statistik:</p>\r\n      <ul>\r\n        <li><b>Reni Yulianti</b></li>\r\n        <li><b>Miranti Rahajeng</b></li>\r\n        <li><b>Chaerul Anwar</b></li>\r\n      </ul>\r\n\r\n      <p><b>Output yang diharapkan</b> dari pembinaan ini mencakup:</p>\r\n      <ul>\r\n        <li>Pembuatan <b>website</b> kelurahan.</li>\r\n        <li>Penyusunan <b>publikasi</b> dan <b>booklet</b>.</li>\r\n        <li>Penerbitan <b>leaflet</b>.</li>\r\n        <li>Pelaksanaan <b>survei</b>.</li>\r\n      </ul>\r\n\r\n      <p><b>Kepala Bappeda Kota Tangerang, Dr. Hj. Yeti Rohaeti</b>, menekankan pentingnya:</p>\r\n      <ul>\r\n        <li><b>Data akurat</b> untuk perencanaan pembangunan dan penganggaran.</li>\r\n        <li>Ketepatan sasaran penyaluran bantuan berbasis data.</li>\r\n        <li>Harapan agar Kelurahan Pabuaran dapat menjadi <b>juara nasional</b> Kelurahan Cantik.</li>\r\n      </ul>\r\n\r\n      <p><b>Ketua Tim Desa Cantik, I Ketut Suarsana</b>, memberikan pembinaan mengenai tahapan <i>GSBPM</i>, meliputi:</p>\r\n      <ul>\r\n        <li>Identifikasi kebutuhan data.</li>\r\n        <li>Desain instrumen dan metode.</li>\r\n        <li>Pengumpulan dan pengolahan data.</li>\r\n        <li>Analisis dan diseminasi.</li>\r\n        <li>Evaluasi hasil.</li>\r\n      </ul>\r\n\r\n      <p><b>Sesi diskusi</b> membahas beberapa hal, antara lain:</p>\r\n      <ul>\r\n        <li>Alasan sensus dilakukan setiap 10 tahun.</li>\r\n        <li>Pemanfaatan data BPS oleh pemerintah.</li>\r\n        <li>Usulan pembuatan <b>bank data sementara</b> di tingkat RT/RW.</li>\r\n      </ul>\r\n\r\n      <p>Acara ditutup dengan <b>penandatanganan Kelurahan Cantik</b>, \r\n      penyerahan sertifikat agen statistik, serta komitmen bersama untuk menyukseskan pembinaan. \r\n      Kegiatan ini memperkuat peran data sebagai fondasi pembangunan kelurahan.\r\n    </p>', '/assets/dokumentasi/pembinaanDCtangkot2.png', '2025-05-06'),
(23, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Tahap 1: Sosialisasi Desa Cinta Statistik 2025', ' <p><b>Sosialisasi Program Desa Cantik 2025</b> oleh <b>Tim Pembina Desa Cantik Provinsi Banten</b> \r\n      dilaksanakan pada <b>Jumat, 2 Mei 2025</b> melalui <i>Zoom Meeting</i> dengan melibatkan peserta dari \r\n      <b>BPS Kota Tangerang</b>, tim pelaksana Desa Cantik, serta perwakilan agen statistik dari kelurahan \r\n      penerima program Desa Cantik tahun 2021–2025. Kegiatan ini menjadi sarana penting untuk menyamakan \r\n      pemahaman sekaligus memperkuat komitmen seluruh pihak yang terlibat dalam implementasi program.</p>\r\n\r\n      <p>Dalam paparannya, <b>Ketua Tim Desa Cantik</b> menjelaskan bahwa program ini memiliki landasan hukum dan \r\n      arah kebijakan yang jelas, yakni <i>UU Statistik</i>, <i>Perpres Satu Data Indonesia</i>, \r\n      <i>Roadmap Reformasi Birokrasi</i>, serta <i>UU Desa</i>. Program Desa Cantik menempatkan desa atau \r\n      kelurahan sebagai <b>subjek pembangunan</b> dengan tujuan meningkatkan literasi statistik, \r\n      menstandarisasi pengelolaan data, mengoptimalkan pemanfaatan data pembangunan, serta membentuk \r\n      <b>agen statistik</b> yang berperan sebagai motor penggerak pengelolaan data di tingkat desa/kelurahan.</p>\r\n\r\n      <p><b>Output pembinaan</b> yang diharapkan dari program ini antara lain:</p>\r\n      <ul>\r\n        <li>Terbangunnya <b>pengelolaan statistik desa/kelurahan</b> yang terstruktur dan berkelanjutan.</li>\r\n        <li>Terbentuknya <b>agen statistik</b> desa/kelurahan yang berkompeten.</li>\r\n        <li>Penerbitan <b>piagam penghargaan</b> bagi desa/kelurahan yang berhasil.</li>\r\n        <li>Publikasi statistik berupa <i>monografi/profil desa</i>, <i>publikasi tematik</i>, hingga <b>website resmi</b> sebagai media diseminasi data.</li>\r\n        <li>Adanya <b>pemilihan Desa Cantik terbaik</b> sebagai bentuk apresiasi atas kinerja dan inovasi.</li>\r\n      </ul>\r\n\r\n      <p>Sementara itu, <b>kriteria pemilihan desa/kelurahan Cantik</b> meliputi: \r\n      belum pernah diajukan sebelumnya, memiliki lokasi yang relatif dekat dengan kantor BPS setempat, \r\n      tersedianya fasilitas internet dan perangkat komputer yang memadai, serta aparat desa/kelurahan \r\n      yang mampu mengoperasikan teknologi tersebut. Hal ini dipandang penting agar program dapat berjalan efektif \r\n      dan memberikan hasil nyata di lapangan.</p>\r\n\r\n      <p>Melalui sosialisasi ini, diharapkan seluruh peserta memperoleh pemahaman menyeluruh mengenai \r\n      arah kebijakan, tujuan, serta tahapan pelaksanaan Desa Cantik. Lebih jauh lagi, program ini diharapkan \r\n      dapat <b>memperkuat kapasitas desa/kelurahan</b> dalam mengelola dan memanfaatkan data sebagai dasar \r\n      pembangunan yang lebih tepat sasaran, berkelanjutan, dan selaras dengan semangat \r\n      <i><b>Satu Data Indonesia</b></i>.\r\n    </p>', '/assets/dokumentasi/pembinaanDCtangkot1.png', '2025-05-02'),
(24, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Tahap 3: Persiapan Pengumpulan Data Lapangan Kelurahan Pabuaran', ' <p><b>Rapat Persiapan Pengumpulan Data Lapangan Kelurahan Pabuaran</b> \r\n      dilaksanakan pada <b>Jumat, 20 Juni 2025</b>, pukul <b>13.30 WIB</b> di Aula Kelurahan Pabuaran. \r\n      Acara ini dihadiri oleh <b>BPS Kota Tangerang</b>, aparat kelurahan, tim Desa Cantik, agen statistik, dan PSM.</p>\r\n\r\n      <p><b>Lurah Pabuaran, Agus Suhendar</b>, menekankan bahwa:</p>\r\n      <ul>\r\n        <li>Pendataan pengangguran menjadi dasar <b>kebijakan pengurangan angka pengangguran</b>.</li>\r\n      </ul>\r\n\r\n      <p><b>Kepala BPS Kota Tangerang, Muladi Widastomo</b>, menyoroti hal penting berikut:</p>\r\n      <ul>\r\n        <li>Sinergi antara <b>BPS</b> dan <b>pemerintah kelurahan</b> sangat dibutuhkan.</li>\r\n        <li>Data yang dihasilkan harus berkualitas sesuai <i>kaidah statistik</i>.</li>\r\n      </ul>\r\n\r\n      <p><b>Ketua Tim Desa Cantik, I Ketut Suarsana</b>, memaparkan tahapan pengumpulan data sesuai <i>GSBPM</i>, meliputi:</p>\r\n      <ul>\r\n        <li>Perancangan output.</li>\r\n        <li>Penentuan variabel.</li>\r\n        <li>Pemilihan metode pengumpulan.</li>\r\n        <li>Penyusunan alur kerja.</li>\r\n      </ul>\r\n\r\n      <p>Beliau juga menegaskan perlunya:</p>\r\n      <ul>\r\n        <li>Pemanfaatan <b>data primer</b> maupun <b>sekunder</b>.</li>\r\n        <li>Kesiapan sumber daya dalam pelaksanaan.</li>\r\n      </ul>\r\n\r\n      <p><b>Miranti Rahajeng</b> bersama <b>Anisa Rima Rahmawati</b> menyampaikan urgensi pendataan lengkap pengangguran di Kelurahan Pabuaran dengan mengacu pada <b>konsep dan definisi ketenagakerjaan</b>, meliputi:</p>\r\n      <ul>\r\n        <li>Klasifikasi usia kerja.</li>\r\n        <li>Angkatan kerja.</li>\r\n        <li>Bukan angkatan kerja.</li>\r\n        <li>Definisi bekerja dan pengangguran.</li>\r\n      </ul>\r\n\r\n      <p>Rapat ini menjadi <b>langkah awal strategis</b> untuk memastikan tersedianya \r\n      data ketenagakerjaan yang <b>valid</b> sebagai dasar program <b>pemberdayaan masyarakat</b>.\r\n    </p>', '/assets/dokumentasi/pembinaanDCtangkot3.png', '2025-06-20'),
(25, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Tahap 4: Pembahasan Tahapan GSBPM Pasca Pengumpulan Data', ' <p><b>Rapat Persiapan Pengumpulan Data Lapangan Kelurahan Pabuaran</b> \r\n      dilaksanakan pada <b>Jumat, 20 Juni 2025</b>, pukul <b>13.30 WIB</b> di Aula Kelurahan Pabuaran. \r\n      Acara ini dihadiri oleh <b>BPS Kota Tangerang</b>, aparat kelurahan, tim Desa Cantik, agen statistik, dan PSM.</p>\r\n\r\n      <p><b>Lurah Pabuaran, Agus Suhendar</b>, menekankan bahwa:</p>\r\n      <ul>\r\n        <li>Pendataan pengangguran menjadi dasar <b>kebijakan pengurangan angka pengangguran</b>.</li>\r\n      </ul>\r\n\r\n      <p><b>Kepala BPS Kota Tangerang, Muladi Widastomo</b>, menyoroti hal penting berikut:</p>\r\n      <ul>\r\n        <li>Sinergi antara <b>BPS</b> dan <b>pemerintah kelurahan</b> sangat dibutuhkan.</li>\r\n        <li>Data yang dihasilkan harus berkualitas sesuai <i>kaidah statistik</i>.</li>\r\n      </ul>\r\n\r\n      <p><b>Ketua Tim Desa Cantik, I Ketut Suarsana</b>, memaparkan tahapan pengumpulan data sesuai <i>GSBPM</i>, meliputi:</p>\r\n      <ul>\r\n        <li>Perancangan output.</li>\r\n        <li>Penentuan variabel.</li>\r\n        <li>Pemilihan metode pengumpulan.</li>\r\n        <li>Penyusunan alur kerja.</li>\r\n      </ul>\r\n\r\n      <p>Beliau juga menegaskan perlunya:</p>\r\n      <ul>\r\n        <li>Pemanfaatan <b>data primer</b> maupun <b>sekunder</b>.</li>\r\n        <li>Kesiapan sumber daya dalam pelaksanaan.</li>\r\n      </ul>\r\n\r\n      <p><b>Miranti Rahajeng</b> bersama <b>Anisa Rima Rahmawati</b> menyampaikan urgensi pendataan lengkap pengangguran di Kelurahan Pabuaran dengan mengacu pada <b>konsep dan definisi ketenagakerjaan</b>, meliputi:</p>\r\n      <ul>\r\n        <li>Klasifikasi usia kerja.</li>\r\n        <li>Angkatan kerja.</li>\r\n        <li>Bukan angkatan kerja.</li>\r\n        <li>Definisi bekerja dan pengangguran.</li>\r\n      </ul>\r\n\r\n      <p>Rapat ini menjadi <b>langkah awal strategis</b> untuk memastikan tersedianya \r\n      data ketenagakerjaan yang <b>valid</b> sebagai dasar program <b>pemberdayaan masyarakat</b>.</p>\r\n\r\n      <p><b>Ringkasan acara lanjutan (8 Juli 2025)</b> menekankan kelanjutan tahapan <i>GSBPM</i> pasca pengumpulan data, yaitu:</p>\r\n      <ul>\r\n        <li><b>Pengolahan data</b> untuk mengubah data mentah menjadi informasi yang bermakna.</li>\r\n        <li><b>Analisis</b> dengan metode statistik yang tepat untuk menghasilkan informasi relevan.</li>\r\n        <li><b>Diseminasi</b> melalui infografis dan publikasi agar mudah dipahami masyarakat.</li>\r\n        <li><b>Evaluasi</b> terhadap SOP, variabel, dan penyajian data untuk perbaikan berkelanjutan.</li>\r\n      </ul>\r\n\r\n      <p>Selain itu, dipaparkan pula hasil pendataan pengangguran di beberapa RW:</p>\r\n      <ul>\r\n        <li>Tingkat partisipasi angkatan kerja: <b>60,34%</b>.</li>\r\n        <li>Tingkat pengangguran terbuka: <b>2,30%</b>.</li>\r\n        <li>Mayoritas penganggur adalah <b>laki-laki (76,92%)</b>, usia <b>20–24 tahun</b>, lulusan <b>SMA (84,62%)</b>.</li>\r\n        <li>Sebagian besar belum mengikuti pelatihan (92,31%) dan belum mendaftar ke bursa tenaga kerja (80,77%).</li>\r\n        <li>Minat tinggi terhadap pelatihan kerja (96,15%), terutama <i>pelatihan konten kreator</i>.</li>\r\n      </ul>\r\n\r\n      <p>Temuan ini menjadi dasar bagi kebijakan <b>pemberdayaan masyarakat</b>, khususnya dalam \r\n      pengembangan keterampilan kerja yang relevan dengan kebutuhan zaman.\r\n    </p>', '/assets/dokumentasi/pembinaanDCtangkot4.png', '2025-07-08'),
(26, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Cilegon Tahap 1: Pembinaan Desa Cantik dan Literasi Statistik', ' <p><b>Rapat Pembinaan Desa Cantik dan Literasi Statistik Pertama</b> di Kelurahan Citangkil \r\n      dilaksanakan pada <b>26 Mei 2025</b> di <b>BPS Kota Cilegon</b>, dipimpin oleh <b>Dadan Sudarmadi</b> \r\n      dan ditulis oleh <b>Raisa Meidy Mustapa</b>. \r\n      Acara ini menjadi langkah awal penting dalam membangun literasi statistik di tingkat kelurahan.</p>\r\n\r\n      <p><b>Empat agenda utama</b> yang dibahas meliputi:</p>\r\n      <ul>\r\n        <li>Pembinaan terkait <i>Generic Statistical Business Process Model (GSBPM)</i> hingga penyajian data.</li>\r\n        <li>Pengenalan <b>Google Sites</b> dan <b>Google Form</b> sebagai media pengelolaan data daring.</li>\r\n        <li>Identifikasi kebutuhan data melalui <b>kuesioner updating</b>.</li>\r\n        <li>Pelatihan petugas serta sosialisasi mekanisme <b>updating data</b>.</li>\r\n      </ul>\r\n\r\n      <p>Peserta terlibat secara aktif dalam:</p>\r\n      <ul>\r\n        <li>Praktik teknis penggunaan aplikasi.</li>\r\n        <li>Diskusi mengenai kendala dan solusi teknis.</li>\r\n        <li>Simulasi pengelolaan data berbasis <i>website</i> dan pengisian mandiri.</li>\r\n      </ul>\r\n\r\n      <p><b>Sesi tanya jawab</b> menyoroti beberapa hal penting, antara lain:</p>\r\n      <ul>\r\n        <li>Konsep <b>pengangguran</b> menurut BPS.</li>\r\n        <li>Aksesibilitas dan fleksibilitas penggunaan <b>Google Sites</b>.</li>\r\n        <li>Penambahan menu informasi pada website.</li>\r\n        <li>Solusi bagi responden <i>lanjut usia</i> yang kesulitan mengisi <b>Google Form</b>, yaitu dengan bantuan agen statistik.</li>\r\n      </ul>\r\n\r\n      <p><b>Tindak lanjut</b> dari rapat ini mencakup:</p>\r\n      <ul>\r\n        <li>Penyusunan <b>rencana teknis output data</b>.</li>\r\n        <li>Revisi instrumen <b>kuesioner updating</b>.</li>\r\n        <li>Penetapan <b>jadwal updating</b> dengan pembagian peran RT/RW.</li>\r\n      </ul>\r\n\r\n      <p><b>Manfaat strategis</b> yang diperoleh peserta adalah:</p>\r\n      <ul>\r\n        <li>Peningkatan pemahaman terhadap <b>GSBPM</b>.</li>\r\n        <li>Penguasaan teknologi daring untuk mendukung pengelolaan data.</li>\r\n        <li>Integrasi proses pengumpulan dan penyajian data secara digital.</li>\r\n        <li>Keterlibatan aktif masyarakat dalam literasi statistik.</li>\r\n      </ul>\r\n\r\n      <p><b>Kesimpulan:</b> Kegiatan pembinaan ini menjadi <b>langkah penting</b> \r\n      dalam memperkuat kapasitas aparat dan masyarakat Kelurahan Citangkil \r\n      dalam <i>pengelolaan data berbasis digital</i> yang efektif dan berkelanjutan.\r\n    </p>', '/assets/dokumentasi/pembinaanDCcilegon1.png', '2025-05-26'),
(27, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Cilegon Tahap 2: Literasi Statistik ke Aparat Kelurahan (Pengenalan GSBPM)', '<p><b>Rapat Literasi Statistik Kelurahan Citangkil</b> dilaksanakan pada <b>Rabu, 6 Agustus 2025</b>, dipimpin sekaligus dicatat oleh <b>Raisa Meidy Mustapa</b>. Fokus utama kegiatan adalah pengenalan <i>Generic Statistical Business Process Model</i> (<b>GSBPM</b>) sebagai kerangka internasional dalam pengelolaan siklus produksi data statistik.</p>\r\n\r\n      <p><b>Agenda kegiatan meliputi:</b></p>\r\n      <ul>\r\n        <li>Pengantar literasi statistik.</li>\r\n        <li>Pemaparan konsep GSBPM.</li>\r\n        <li>Penjelasan tahapan proses bisnis statistik.</li>\r\n        <li>Sesi diskusi interaktif.</li>\r\n        <li>Rencana tindak lanjut.</li>\r\n      </ul>\r\n\r\n      <p><b>Materi utama</b> mencakup:</p>\r\n      <ul>\r\n        <li>Definisi GSBPM sebagai model internasional pengelolaan data.</li>\r\n        <li>Tujuan penerapan: memastikan data dikelola secara konsisten dan akuntabel.</li>\r\n        <li>Delapan tahapan utama mulai dari <i>specify needs</i> hingga <i>evaluate</i>.</li>\r\n      </ul>\r\n\r\n      <p><b>Hasil diskusi:</b></p>\r\n      <ul>\r\n        <li>GSBPM dapat diterapkan dalam pengelolaan data lokal, seperti updating kependudukan, potensi desa, dan data sektoral kelurahan.</li>\r\n        <li>Aparat kelurahan menekankan pentingnya pencatatan proses agar setiap langkah terdokumentasi dengan baik.</li>\r\n        <li>Pertanyaan mengenai integrasi GSBPM dengan website Desa Cantik dan publikasi kelurahan dijawab dengan penegasan bahwa model ini menjaga validitas, konsistensi, serta keterjangkauan data.</li>\r\n      </ul>\r\n\r\n      <p><b>Kesimpulan:</b><br>\r\n      Penerapan <b>GSBPM</b> dinilai sangat relevan untuk meningkatkan kualitas tata kelola data di tingkat kelurahan sekaligus mendukung prinsip <i>pembangunan berbasis data</i>, yang menjadi tujuan utama program <b>Desa Cantik</b>.\r\n    </p>', '/assets/dokumentasi/pembinaanDCcilegon2.png', '2025-08-06'),
(28, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 1', ' <p><b>Notulensi Pembinaan Desa Cantik di Kelurahan Curug</b> dilaksanakan pada <b>14 Mei 2025</b> di Aula Kelurahan Curug. Kegiatan ini dihadiri oleh <b>aparat kelurahan</b>, <b>ketua RW</b>, beberapa <b>ketua RT</b>, serta perwakilan dari <b>BPS Kota Serang</b>. Acara dibuka dengan sambutan dan arahan dari <b>Lurah Curug, Bu Sutihat</b>, yang menekankan pentingnya partisipasi masyarakat dalam mendukung program Desa Cantik.</p>\r\n\r\n      <p><b>Materi utama</b> yang disampaikan dalam kegiatan ini meliputi:</p>\r\n      <ul>\r\n        <li><b>Teknik pengumpulan data</b> untuk memastikan informasi yang diperoleh dari warga bersifat akurat dan dapat dipertanggungjawabkan.</li>\r\n        <li>Pengenalan <i>Survei Preneur</i>, yaitu kegiatan pengumpulan data ketenagakerjaan yang dirancang untuk <b>menjaring wirausaha dan calon wirausaha</b> di Kelurahan Curug.</li>\r\n      </ul>\r\n\r\n      <p><b>Survei Preneur</b> memiliki beberapa poin penting, antara lain:</p>\r\n      <ul>\r\n        <li>Dilaksanakan secara <b>daring</b> melalui tautan resmi: <a href=\"https://s.bps.go.id/Survei_Preneur\"><b>s.bps.go.id/Survei_Preneur</b></a>.</li>\r\n        <li><b>Tata cara pengisian</b> dijelaskan secara rinci agar peserta pembinaan dapat menyampaikan informasi tersebut kepada warga di masing-masing RT.</li>\r\n        <li>Data yang dikumpulkan mencakup identitas dasar responden, status ketenagakerjaan, pengalaman usaha, serta minat dalam mengembangkan usaha baru.</li>\r\n      </ul>\r\n\r\n      <p><b>Tujuan utama</b> survei ini adalah:</p>\r\n      <ul>\r\n        <li>Mendukung pemetaan potensi kewirausahaan di Kelurahan Curug.</li>\r\n        <li>Memberikan gambaran yang jelas tentang kondisi tenaga kerja dan calon wirausaha lokal.</li>\r\n        <li>Menjadi dasar perumusan kebijakan serta program <b>pemberdayaan masyarakat berbasis data</b>.</li>\r\n      </ul>\r\n\r\n      <p>Melalui kegiatan ini, diharapkan Kelurahan Curug mampu mengelola data kewirausahaan secara lebih <b>terstruktur, akurat, dan partisipatif</b>, sekaligus memperkuat peran <b>Desa Cantik</b> dalam pembangunan berbasis statistik.\r\n    </p>', '/assets/dokumentasi/pembinaanDCserkot1.png', '2025-05-14'),
(29, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 2', '<p><b>Pembinaan Desa Cantik Kelurahan Curug</b> pada <b>21 Mei 2025</b> bertempat di Aula Kelurahan dan dihadiri oleh <b>aparat kelurahan</b>, <b>ketua RW</b>, <b>ketua RT</b>, serta <b>BPS Kota Serang</b>. Acara dibuka dengan sambutan dari <b>Lurah Curug, Bu Sutihat</b>, yang menekankan pentingnya kegiatan ini dalam mendukung pembangunan berbasis data di tingkat kelurahan.</p>\r\n\r\n      <p><b>Materi utama</b> difokuskan pada pengenalan <i>Survei Preneur</i>. Survei ini memiliki tujuan utama untuk memperoleh <b>statistik ketenagakerjaan</b>, khususnya dalam rangka <b>menjaring wirausaha dan calon wirausaha</b> di Kelurahan Curug.</p>\r\n\r\n      <p><b>Tata cara pengisian Survei Preneur</b> dijelaskan kepada para peserta pembinaan agar dapat diteruskan kepada warga melalui masing-masing ketua RT, dengan mekanisme <b>pengisian daring</b> pada tautan resmi: \r\n      <a href=\"https://s.bps.go.id/Survei_Preneur\" style=\"color:blue;\"><i>s.bps.go.id/Survei_Preneur</i></a>.</p>\r\n\r\n      <p><b>Kendala utama</b> yang ditemukan dalam pelaksanaan survei ini adalah:</p>\r\n      <ul>\r\n        <li><b>Capaian survei masih rendah</b> hampir di seluruh RT.</li>\r\n        <li>Keterbatasan kemampuan sebagian ketua RT dan warga dalam mengakses serta mengisi survei secara online.</li>\r\n      </ul>\r\n\r\n      <p><b>Ringkasan Inti Rapat:</b></p>\r\n      <ul>\r\n        <li><i>Survei Preneur</i> menjadi instrumen penting dalam memetakan potensi kewirausahaan di Kelurahan Curug.</li>\r\n        <li>Perlu peningkatan <b>literasi digital</b> aparat RT dan warga untuk mendorong partisipasi yang lebih luas.</li>\r\n        <li>Kegiatan tindak lanjut pembinaan akan difokuskan pada solusi teknis serta pendampingan agar pengisian survei lebih mudah dan merata.</li>\r\n      </ul>\r\n\r\n      <p>Kegiatan pembinaan ini diharapkan menjadi langkah awal memperkuat peran <b>Desa Cantik</b> dalam mengelola data kewirausahaan secara lebih <b>akurat, partisipatif, dan bermanfaat</b> untuk pembangunan kelurahan.\r\n    </p>', '/assets/dokumentasi/pembinaanDCserkot2.png', '2025-05-21'),
(30, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 3', '<p><b>Notulensi Pembinaan Desa Cantik Kelurahan Curug</b> pada <b>28 Mei 2025</b> dilaksanakan di Aula Kelurahan Curug dan dihadiri oleh <b>aparat kelurahan</b> serta <b>BPS Kota Serang</b>. Kegiatan ini menjadi bagian penting dalam memperkuat kapasitas kelurahan dalam pengelolaan dan pemanfaatan data statistik.</p>\r\n\r\n      <p><b>Materi pembinaan</b> berfokus pada <b>teknik penyajian data</b>, dengan penekanan bahwa data tidak hanya berhenti pada tahap pengumpulan, tetapi harus disajikan dalam berbagai bentuk agar lebih mudah dipahami masyarakat, seperti:</p>\r\n      <ul>\r\n        <li>Tabel statistik yang sistematis.</li>\r\n        <li>Grafik sebagai visualisasi tren data.</li>\r\n        <li>Infografis yang komunikatif dan menarik.</li>\r\n        <li>Buku publikasi yang terstruktur.</li>\r\n      </ul>\r\n\r\n      <p><b>Target utama</b> dari kegiatan ini adalah penerbitan <b>Buku Kelurahan Curug dalam Angka 2024</b>, sebagai publikasi resmi yang dapat digunakan untuk mendukung perencanaan pembangunan di tingkat kelurahan.</p>\r\n\r\n      <p><b>Perkembangan Survei Preneur</b> juga dilaporkan dalam rapat ini. Hingga saat ini, survei telah diisi oleh <b>454 penduduk usia 15 tahun ke atas</b>, atau sekitar <b>13 persen</b> dari target responden. Angka ini menunjukkan bahwa capaian masih perlu ditingkatkan agar hasil survei lebih representatif.</p>\r\n\r\n      <p><b>Poin penting</b> yang menjadi perhatian bersama:</p>\r\n      <ul>\r\n        <li>Perlu adanya <b>dukungan lebih lanjut dari Lurah</b> dan aparat kelurahan.</li>\r\n        <li>Ketua RT perlu lebih aktif dalam mendorong partisipasi warganya.</li>\r\n        <li>Keberhasilan pelaksanaan <i>Survei Preneur</i> sangat bergantung pada tingkat partisipasi masyarakat.</li>\r\n      </ul>\r\n\r\n      <p>Secara keseluruhan, kegiatan pembinaan ini menjadi langkah nyata dalam mendorong <b>pengelolaan data yang lebih baik</b>, sekaligus memastikan kelurahan memiliki publikasi statistik yang kredibel dan bermanfaat.\r\n    </p>', '/assets/dokumentasi/pembinaanDCserkot3.png', '2025-05-28'),
(31, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 4', ' <p><b>Pembinaan Desa/Kelurahan Cantik</b> kali ini difokuskan pada <b>penyusunan publikasi Kelurahan Curug dalam Angka</b>. Kegiatan ini diikuti oleh <b>tiga aparat staf kelurahan</b> yang memiliki kemampuan mengoperasikan <i>Microsoft Word</i> dan <i>Excel</i>, serta <b>tiga pegawai organik BPS Kota Serang</b>.</p>\r\n\r\n      <p><b>Publikasi yang disusun</b> mengacu pada:</p>\r\n      <ul>\r\n        <li><b>Kecamatan dalam Angka</b></li>\r\n        <li><b>Kota Serang dalam Angka</b></li>\r\n      </ul>\r\n\r\n      <p><b>Sumber data</b> diperoleh dari:</p>\r\n      <ul>\r\n        <li>Kelurahan Curug</li>\r\n        <li>Instansi terkait di tingkat kelurahan</li>\r\n        <li>Kecamatan</li>\r\n        <li>Kota Serang</li>\r\n      </ul>\r\n\r\n      <p><b>Rencana penyelesaian publikasi</b> ditargetkan pada <b>pertengahan Juli 2025</b>. Oleh karena itu, diperlukan <b>koordinasi dan konsolidasi data secara intensif</b> agar publikasi dapat tersusun dengan baik, lengkap, dan tepat waktu.\r\n    </p>', '/assets/dokumentasi/pembinaanDCserkot4.png', '2025-05-04'),
(32, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 5', '<p><b>Pembinaan kali ini</b> difokuskan pada <b>pengolahan data menggunakan aplikasi SPSS 22</b>. \r\n    Peserta yang direncanakan berjumlah <b>tiga orang staf kelurahan</b>, namun yang hadir hanya <b>dua orang</b> karena satu peserta berhalangan. \r\n    Sebelumnya, <i>SPSS 22</i> telah berhasil diinstal pada dua laptop yang digunakan dalam pelatihan.</p>\r\n\r\n    <p><b>Materi pembelajaran</b> menggunakan <i>raw data Survei Preneur</i> yang sudah selesai dikumpulkan. \r\n    Langkah awal dilakukan <b>pemeriksaan serta validasi data</b> untuk mengidentifikasi kesalahan dan ketidakkonsistenan. \r\n    Walaupun proses pemeriksaan data belum selesai, peserta langsung diajarkan:</p>\r\n\r\n    <ul>\r\n      <li>Cara membuat <b>tabulasi data</b>.</li>\r\n      <li>Praktik langsung pengolahan data menggunakan <i>SPSS 22</i>.</li>\r\n    </ul>', '/assets/dokumentasi/pembinaanDCserkot5.png', '2025-06-11'),
(33, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 6', '<p><b>Pembinaan pada pertemuan keenam</b> masih difokuskan pada <b>pengolahan data menggunakan aplikasi SPSS 22</b> \r\n    dengan melibatkan <b>tiga orang agen statistik</b> dari aparat kelurahan. \r\n    Materi menggunakan <i>raw data Survei Preneur</i> yang telah terkumpul.</p>\r\n\r\n    <p>Kegiatan dimulai dengan <b>pemeriksaan dan validasi data</b> untuk memastikan tidak ada kesalahan atau ketidakkonsistenan. \r\n    Selanjutnya, agen statistik diajarkan cara membuat <b>tabel-tabel sederhana</b> dari hasil <i>Survei Preneur</i> \r\n    dan langsung mempraktikkannya.</p>\r\n\r\n    <ul>\r\n      <li>Peserta berhasil menyusun beberapa tabel sederhana.</li>\r\n      <li>Agen statistik didorong untuk terus mencoba secara mandiri.</li>\r\n      <li>Pentingnya memperdalam pemahaman pengolahan data menggunakan <i>SPSS</i> ditekankan dalam kegiatan ini.</li>\r\n    </ul>', '/assets/dokumentasi/pembinaanDCserkot6.png', '2025-06-18'),
(34, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 7', '<p>\r\n      Pembinaan Desa/Kelurahan Cantik kali ini membahas <b>teknik membuat infografis</b> dengan menghadirkan pemateri dari tim <i>Pojok Statistik UNIBA Serang</i> serta Pembina Desa Cantik BPS Provinsi Banten. \r\n      Kegiatan ini memberikan wawasan kepada peserta mengenai pentingnya infografis sebagai sarana penyajian data yang menarik, informatif, dan mudah dipahami oleh masyarakat luas. \r\n    </p>\r\n\r\n    <p>\r\n      Peserta diperkenalkan pada berbagai aplikasi yang dapat digunakan untuk menyusun dan mendesain infografis, di antaranya <i>Adobe</i>, <i>PowerPoint</i>, <i>Canva</i>, maupun aplikasi daring lainnya. \r\n      Dari penjelasan pemateri, ditekankan bahwa penggunaan <i>Adobe</i> dan <i>PowerPoint</i> lebih disarankan karena memiliki fleksibilitas yang tinggi, fitur desain yang lebih lengkap, serta menghasilkan tampilan grafis yang lebih optimal dan profesional untuk kebutuhan publikasi data kelurahan. \r\n    </p>\r\n\r\n    <ul>\r\n      <li><b>Adobe</b> → lebih fleksibel, mendukung desain detail, hasilnya profesional.</li>\r\n      <li><b>PowerPoint</b> → mudah dioperasikan, familiar bagi staf kelurahan, hasil tetap optimal.</li>\r\n      <li><b>Canva</b> → praktis dan berbasis daring, cocok untuk desain cepat.</li>\r\n      <li><b>Aplikasi daring lain</b> → dapat dimanfaatkan sesuai kebutuhan dan ketersediaan.</li>\r\n    </ul>', '/assets/dokumentasi/pembinaanDCserkot7.png', '2025-06-25');
INSERT INTO `tb_dokumentasi` (`id`, `title`, `desk`, `img`, `date`) VALUES
(35, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 8', '<p><b>Pembinaan Program Desa Cinta Statistik (Desa Cantik) Kota Serang Tahap 8</b> \r\n    dilaksanakan pada <b>02 Juli 2025</b> di <b>Kota Serang</b> dengan peserta sebanyak \r\n    <b>tujuh agen statistik</b> dari aparat kelurahan. \r\n    Kegiatan ini difokuskan pada <b>teknik menyajikan dan memaparkan data menggunakan PowerPoint</b> \r\n    untuk meningkatkan kemampuan peserta dalam mengolah serta menyampaikan data secara efektif.\r\n    </p>\r\n\r\n    <p><b>Materi utama</b> yang disampaikan meliputi:</p>\r\n    <ul>\r\n      <li>Pentingnya penyajian data dalam bentuk <i>point-point singkat</i> agar lebih ringkas, terstruktur, dan mudah dipahami audiens.</li>\r\n      <li>Pemanfaatan tabel dan grafik sebagai sarana visualisasi utama untuk menyederhanakan data yang kompleks.</li>\r\n      <li>Penggunaan infografis sebagai elemen tambahan agar data lebih menarik, komunikatif, dan memperkuat pesan utama.</li>\r\n    </ul>\r\n\r\n    <p><b>Manfaat strategis</b> dari pembinaan ini adalah:</p>\r\n    <ul>\r\n      <li>Meningkatkan keterampilan peserta dalam menyusun presentasi data yang efektif.</li>\r\n      <li>Mendorong penggunaan media visual yang tepat untuk mendukung pemahaman audiens.</li>\r\n      <li>Membangun kapasitas aparat kelurahan dalam menyajikan data secara profesional.</li>\r\n    </ul>\r\n\r\n    <p><b>Kesimpulan:</b> Kegiatan pembinaan ini menjadi <b>langkah penting</b> dalam \r\n        memperkuat kemampuan aparat kelurahan untuk menyajikan data dengan media presentasi yang lebih \r\n        menarik, komunikatif, dan mudah dipahami, sehingga mendukung terciptanya budaya statistik yang lebih baik.\r\n    </p>', '/assets/dokumentasi/pembinaanDCserkot8.png', '2025-07-02'),
(36, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 9', '<p><b>Pembinaan Desa Cantik</b> kali ini menghadirkan <b>Tim Pembina BPS Provinsi Banten</b> serta <b>Pembina BPS Kota Serang</b> sebagai narasumber. \r\n      Peserta kegiatan terdiri dari <b>agen statistik aparat kelurahan</b>, <b>mahasiswa UPG</b> yang sedang melaksanakan KKM, serta <b>tim Pembina Desa Cantik BPS Kota Serang</b>. \r\n      Kegiatan ini menjadi wadah penting untuk memperluas wawasan statistik di tingkat kelurahan.</p>\r\n\r\n      <p><b>Materi utama</b> yang dipaparkan meliputi:</p>\r\n      <ul>\r\n        <li><b>Statistik kriminalitas</b> oleh BPS Provinsi Banten.</li>\r\n        <li><b>Profil Kelurahan Curug</b> beserta <b>statistik ketenagakerjaan</b> oleh BPS Kota Serang.</li>\r\n      </ul>\r\n\r\n      <p><b>Sesi tanya jawab</b> kemudian dilaksanakan sebagai upaya untuk memperdalam pemahaman peserta terhadap materi yang telah disampaikan. \r\n      Diskusi ini membuka ruang klarifikasi konsep serta penerapan statistik pada isu-isu yang relevan di wilayah kelurahan.</p>\r\n\r\n      <p><b>Kesimpulan:</b> Pembinaan ini menjadi <b>langkah strategis</b> dalam meningkatkan kapasitas literasi statistik aparat kelurahan, mahasiswa, \r\n      dan agen statistik sehingga mampu mendukung pembangunan berbasis data yang akurat dan bermanfaat.\r\n    </p>', '/assets/dokumentasi/pembinaanDCserkot9.png', '2025-07-09'),
(37, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Serang Tahap 10', '<p><b>Pembinaan Desa Cantik</b> kali ini berfokus pada <b>penyelesaian penyusunan Publikasi Kelurahan Curug dalam Angka</b> \r\n      dengan peserta utama dari <b>agen statistik kelurahan</b>. \r\n      Kegiatan ini diarahkan untuk meninjau kembali <b>kelengkapan data</b> yang sudah dihimpun, mengidentifikasi <b>tabel-tabel kosong</b>, \r\n      serta menelusuri <b>sumber data tambahan</b> yang diperlukan agar publikasi dapat tersusun secara lengkap dan akurat.</p>\r\n\r\n      <p><b>Pembahasan utama</b> dalam kegiatan ini meliputi:</p>\r\n      <ul>\r\n        <li>Meninjau kelengkapan data yang telah dikumpulkan.</li>\r\n        <li>Mengidentifikasi tabel-tabel yang masih kosong dan perlu dilengkapi.</li>\r\n        <li>Menelusuri serta memastikan sumber data yang sahih dan relevan.</li>\r\n        <li>Mendiskusikan kebutuhan penambahan tabel penting terkait kondisi Kelurahan Curug.</li>\r\n      </ul>\r\n\r\n      <p>Pada sektor <b>pertanian</b>, diputuskan untuk menggunakan <b>data Sensus Pertanian 2023</b> sebagai sumber resmi. \r\n      Hal ini dilakukan untuk memastikan bahwa informasi yang disajikan dalam publikasi sesuai dengan <b>data terbaru</b> \r\n      dan dapat <b>dipertanggungjawabkan secara ilmiah</b>.</p>\r\n\r\n      <p><b>Kesimpulan:</b> Kegiatan ini menjadi <b>tahap krusial</b> dalam memastikan publikasi \r\n      <b>Kelurahan Curug dalam Angka</b> tersusun secara komprehensif, valid, dan siap digunakan sebagai acuan pembangunan.\r\n    </p>', '/assets/dokumentasi/pembinaanDCserkot10.png', '2025-07-16'),
(38, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Selatan Tahap 1: Penerapan Proses Bisnis Statistik (GSBPM)', '<p><b>Pembinaan Desa Cantik ke-1</b> membahas <b>Program Desa Cantik 2025</b> serta penerapan \r\n      <i>Generic Statistical Business Process Model (GSBPM)</i>. \r\n      Materi yang disampaikan mencakup latar belakang, tujuan, output, dan dampak program, \r\n      sebagai dasar penguatan literasi statistik di tingkat desa.</p>\r\n\r\n      <p><b>Tujuan utama Program Desa Cantik</b> adalah:</p>\r\n      <ul>\r\n        <li>Meningkatkan <b>literasi statistik</b> aparat dan masyarakat desa.</li>\r\n        <li>Menstandarkan <b>pengelolaan data</b> di tingkat desa.</li>\r\n        <li>Mengoptimalkan <b>pemanfaatan data pembangunan</b>.</li>\r\n        <li>Membentuk <b>agen statistik desa</b> yang kompeten.</li>\r\n      </ul>\r\n\r\n      <p><b>Output program</b> yang diharapkan meliputi:</p>\r\n      <ul>\r\n        <li><b>Profil/monografi desa</b>.</li>\r\n        <li><b>Publikasi statistik</b> tematik maupun umum.</li>\r\n        <li><b>Website data desa</b> sebagai media diseminasi.</li>\r\n        <li>Penetapan <b>Desa Cantik terbaik</b> sebagai bentuk apresiasi.</li>\r\n      </ul>\r\n\r\n      <p><b>Dampak jangka panjang</b> dari program ini adalah meningkatnya <b>kualitas data desa</b>, \r\n      sehingga dapat mendukung <b>pengambilan keputusan berbasis data</b> \r\n      dan pembangunan yang lebih tepat sasaran.</p>\r\n\r\n      <p><b>Penerapan GSBPM</b> dijelaskan sebagai kerangka kerja standar internasional \r\n      dalam proses statistik, yang terdiri atas tahapan:</p>\r\n      <ul>\r\n        <li><b>Perencanaan</b>: identify needs, design, build.</li>\r\n        <li><b>Pengumpulan data</b>: collect.</li>\r\n        <li><b>Pengolahan dan analisis</b>: process, analyze.</li>\r\n        <li><b>Penyebarluasan dan evaluasi</b>: disseminate, evaluate.</li>\r\n      </ul>\r\n\r\n      <p>Melalui model ini, <b>data desa</b> dapat dikelola secara <b>sistematis</b>, \r\n      <b>terintegrasi</b>, dan <b>berkelanjutan</b>.</p>\r\n\r\n      <p><b>Hasil diskusi</b> menghasilkan kesepakatan untuk:</p>\r\n      <ul>\r\n        <li>Mengadopsi <b>GSBPM</b> dalam setiap tahapan pengelolaan data desa.</li>\r\n        <li>Mengoptimalkan pemanfaatan <b>data administrasi</b> dan <b>big data</b>.</li>\r\n        <li>Fokus pada <b>peningkatan kapasitas agen statistik</b>.</li>\r\n      </ul>\r\n\r\n      <p><b>Tindak lanjut</b>: Agen statistik akan melaksanakan <b>pengumpulan, pengolahan, dan publikasi data</b> \r\n      sesuai kerangka kerja <b>GSBPM</b> untuk memperkuat budaya statistik di desa.\r\n    </p>', '/assets/dokumentasi/pembinaanDCtangsel1.png', '2025-05-09'),
(39, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Selatan Tahap 2: Identifikasi Kebutuhan Kelurahan (Lanjutan)', '<p><b>Pembinaan Desa Cantik di Kelurahan Pakulonan</b> difokuskan pada \r\n      <b>identifikasi potensi</b> dan <b>kebutuhan data</b> sebagai langkah awal \r\n      dalam penerapan <b>Program Cinta Statistik 2025</b>.</p>\r\n\r\n      <p><b>Hasil diskusi</b> menghasilkan beberapa poin penting, antara lain:</p>\r\n      <ul>\r\n        <li>Belum tersedianya <b>data monografi terbaru</b>.</li>\r\n        <li>Belum adanya <b>sistem informasi desa (SID)</b> yang memadai.</li>\r\n        <li><b>Ketiadaan website kelurahan</b> sebagai media informasi publik.</li>\r\n      </ul>\r\n\r\n      <p><b>Potensi unggulan Kelurahan Pakulonan</b> yang dapat dikembangkan:</p>\r\n      <ul>\r\n        <li><b>Persebaran UMKM</b> yang cukup merata di berbagai wilayah.</li>\r\n        <li><b>Daya tarik wisata kuliner</b> di beberapa lokasi strategis.</li>\r\n      </ul>\r\n\r\n      <p><b>Tindak lanjut utama</b> yang disepakati adalah melakukan \r\n      <b>pembaruan data monografi</b> agar informasi dasar kelurahan lebih akurat dan mutakhir. \r\n      Selain itu, <b>Tim Pembina Desa Cantik</b> akan memberikan \r\n      <b>pembinaan lanjutan</b> mengenai pengelolaan dan pemanfaatan data statistik.</p>\r\n\r\n      <p>Langkah ini diharapkan dapat <b>memperkuat kapasitas kelurahan</b> \r\n      dalam menyediakan data berkualitas sekaligus \r\n      <b>mendorong perencanaan pembangunan berbasis potensi lokal</b>.\r\n    </p>  ', '/assets/dokumentasi/pembinaanDCtangsel2.png', '2025-05-16'),
(40, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Selatan Tahap 3: Penyajian Data dengan Tabel dan Grafik', '<p><b>Pembinaan kali ini</b> berfokus pada <b>penyajian data</b> dengan <b>tabel</b> dan <b>grafik</b> \r\n      serta <b>teknik penyebarluasan data</b>.</p>\r\n\r\n      <p><b>Materi yang disampaikan</b> meliputi:</p>\r\n      <ul>\r\n        <li><b>Tabel</b>:\r\n          <ul>\r\n            <li>Tujuan dan komponen penyusunan tabel.</li>\r\n            <li>Jenis-jenis tabel: satu arah, dua arah, tiga arah.</li>\r\n            <li>Teknik penyajian tabel panjang.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Grafik</b>:\r\n          <ul>\r\n            <li>Keunggulan grafik dalam menyampaikan informasi lebih menarik dan mudah dipahami.</li>\r\n            <li>Jenis grafik: garis, batang, lingkaran, piktogram, cartogram.</li>\r\n            <li>Panduan pemilihan grafik sesuai tujuan, jenis data, dan target pengguna.</li>\r\n          </ul>\r\n        </li>\r\n        <li><b>Penyebarluasan data</b>:\r\n          <ul>\r\n            <li>Melalui publikasi, poster, website resmi, dan media sosial.</li>\r\n            <li>Menekankan konsistensi format dan sumber data.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p><b>Sesi praktik</b> meliputi penyusunan tabel dan grafik dengan topik:\r\n      <ul>\r\n        <li>Tabel jumlah apotek, tempat praktik dokter, dan sarana kesehatan.</li>\r\n        <li>Tiga tabel sesuai format BPS.</li>\r\n        <li><i>Grafik Rasio Penduduk Kelurahan Pakulonan Tahun 2021–2024</i>.</li>\r\n        <li><i>Grafik Jumlah Penduduk Berdasarkan Jenis Kelamin Tahun 2024</i>.</li>\r\n        <li><i>Tabel Jumlah Penduduk Berdasarkan Jenis Kelamin dan Rasio Tahun 2021–2024</i>.</li>\r\n      </ul>\r\n      </p>\r\n\r\n      <p><b>Sumber data</b> berasal dari <b>DKB Disdukcapil</b>. Hasil praktik ini menjadi dasar \r\n      peningkatan keterampilan <b>agen statistik</b> dalam mengolah dan menyajikan data \r\n      secara <b>informatif</b> dan sesuai <b>standar</b>.\r\n    </p>', '/assets/dokumentasi/pembinaanDCtangsel3.png', '2025-05-23'),
(41, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Selatan Tahap 4: Analisis Sederhana', '<p><b>Pembinaan kali ini</b> membahas <b>analisis data sederhana</b> dengan fokus pada \r\n      <b>analisis deskriptif</b>. Kegiatan dihadiri oleh <b>Lurah Pakulonan</b>, \r\n      Bapak Dwisantoso, <b>Sekretaris Lurah</b> Bapak Imam Hadi, serta pemateri \r\n      Bapak Ahmad Jailani dan Ibu Santi Nurhayati.</p>\r\n\r\n      <p><b>Sesi pembukaan</b> disampaikan oleh Bapak Imam yang menekankan pentingnya \r\n      <b>pembangunan website kelurahan</b> sesuai dengan kebutuhan spesifik masyarakat, \r\n      bukan sekadar menggunakan <i>template</i> dari Dinas Kominfo.</p>\r\n\r\n      <p><b>Sesi materi</b> dimulai dengan penjelasan dasar analisis data, khususnya \r\n      perbedaan antara <b>statistik deskriptif</b> dan <b>inferensia</b>. \r\n      Peserta kemudian difokuskan pada penerapan analisis deskriptif serta tahapan analisis menurut \r\n      <i>Generic Statistical Business Process Model (GSBPM)</i> yang mencakup:</p>\r\n      <ul>\r\n        <li>Penyusunan naskah output.</li>\r\n        <li>Validasi data.</li>\r\n        <li>Interpretasi output.</li>\r\n        <li>Kebijakan penyajian data.</li>\r\n      </ul>\r\n\r\n      <p><b>Materi lebih lanjut</b> menjelaskan:</p>\r\n      <ul>\r\n        <li>Jenis data:\r\n          <ul>\r\n            <li><b>Kategorik</b>: nominal, ordinal.</li>\r\n            <li><b>Numerik</b>: interval, rasio.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Ukuran statistik dalam analisis deskriptif:\r\n          <ul>\r\n            <li>Rate, rasio, proporsi, jumlah mutlak.</li>\r\n            <li>Ukuran pemusatan: mean, median, modus.</li>\r\n            <li>Ukuran penyebaran: standar deviasi.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>\r\n\r\n      <p><b>Hasil pembinaan</b> diharapkan mampu meningkatkan kapasitas \r\n      <b>agen statistik Pakulonan</b> dalam mengolah data menjadi informasi yang \r\n      <b>jelas</b>, <b>ringkas</b>, dan <b>bermanfaat</b> sebagai dasar pengambilan keputusan \r\n      maupun penyusunan publikasi kelurahan.\r\n    </p>', '/assets/dokumentasi/pembinaanDCtangsel4.png', '2025-05-28'),
(42, 'Pembinaan Program Desa Cinta Statistik (DesaCantik) Kota Tangerang Selatan Tahap 5: Penyajian Data dengan Infografis', '<p><b>Pembinaan kali ini</b> berfokus pada <b>penyajian data dengan infografis</b> \r\n      sebagai strategi komunikasi statistik yang efektif. Materi yang disampaikan mencakup \r\n      definisi infografis sebagai cara memvisualisasikan informasi kompleks agar lebih mudah dipahami, \r\n      serta keunggulannya dalam menyederhanakan penjelasan panjang atau tabel rumit menjadi visual yang menarik.</p>\r\n\r\n      <p><b>Jenis-jenis infografis</b> yang dijelaskan meliputi:</p>\r\n      <ul>\r\n        <li>Infografis <b>statis</b>.</li>\r\n        <li>Infografis <b>dinamis</b> (audio-video).</li>\r\n        <li>Infografis <b>interaktif</b>.</li>\r\n      </ul>\r\n\r\n      <p><b>Elemen penting dalam desain infografis</b> meliputi:</p>\r\n      <ul>\r\n        <li>Kejelasan data.</li>\r\n        <li>Visual yang menarik.</li>\r\n        <li>Kemudahan pemahaman.</li>\r\n        <li>Kemudahan distribusi.</li>\r\n      </ul>\r\n\r\n      <p><b>Langkah-langkah pembuatan infografis</b> yang dipaparkan adalah:</p>\r\n      <ul>\r\n        <li>Pengumpulan data.</li>\r\n        <li>Penentuan tujuan.</li>\r\n        <li>Perencanaan.</li>\r\n        <li>Pemilihan aplikasi (<i>online/offline</i>).</li>\r\n        <li>Evaluasi data.</li>\r\n        <li>Desain.</li>\r\n        <li>Proses rilis.</li>\r\n      </ul>\r\n\r\n      <p><b>Praktik langsung</b> dilakukan dengan menggunakan <b>Canva</b> bertema \r\n      jumlah fasilitas kesehatan di Kelurahan Pakulonan. \r\n      Hasil praktik menunjukkan bahwa agen statistik mulai mampu mengubah data numerik menjadi tampilan visual yang lebih komunikatif, \r\n      sehingga data dapat lebih mudah dipahami masyarakat umum.</p>\r\n\r\n      <p><b>Manfaat kegiatan</b> ini diharapkan dapat meningkatkan keterampilan peserta \r\n      dalam menyebarluaskan data desa secara <b>menarik</b> dan <b>efektif</b> melalui berbagai media.\r\n    </p>', 'assets/dokumentasi/pembinaanDCtangsel5.png', '2025-06-05');

-- --------------------------------------------------------

--
-- Table structure for table `tb_info`
--

CREATE TABLE `tb_info` (
  `id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `desk` text NOT NULL,
  `img` varchar(255) NOT NULL,
  `date` date NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `tb_info`
--

INSERT INTO `tb_info` (`id`, `title`, `desk`, `img`, `date`) VALUES
(1, 'BPS Goes to School: Edukasi Pentingnya Data Kependudukan dan Lembaga Keuangan', '<p>Program <strong>BPS Goes To School</strong> yang dilaksanakan oleh \r\n      <strong>Badan Pusat Statistik (BPS) Provinsi Banten</strong> merupakan salah satu bentuk nyata \r\n      dari upaya meningkatkan literasi statistik di kalangan generasi muda.</p>\r\n\r\n      <p>Kegiatan dilaksanakan di <em>BPK Penabur, SMAK Penabur Serang</em> pada \r\n      <strong>Kamis, 15 Mei 2025</strong> pukul 13.00–16.00 WIB dengan tema: \r\n      <strong>“Stop STECU (Stelan Cuek) terhadap Pentingnya Data Kependudukan dan Lembaga Keuangan.”</strong></p>\r\n\r\n      <p>Tujuan kegiatan ini antara lain:</p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li>Menumbuhkan kesadaran siswa mengenai pentingnya data kependudukan.</li>\r\n        <li>Memahami peran data lembaga keuangan dalam pembangunan nasional.</li>\r\n        <li>Mengenalkan data dengan cara <em>komunikatif</em>, interaktif, dan kontekstual.</li>\r\n      </ul>\r\n\r\n      <p>Kegiatan ini juga bagian dari program <em>Eksposisi Statistik (EKSOTIK)</em> dan \r\n      <em>Pojok Statistik</em>. BPS mendorong generasi muda untuk:</p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li>Aktif berdiskusi dan bertanya.</li>\r\n        <li>Memahami proses penyusunan data statistik.</li>\r\n        <li>Mengetahui manfaat data dalam kehidupan masyarakat.</li>\r\n      </ul>\r\n\r\n      <p>Hal ini sejalan dengan visi membangun budaya <strong>melek data (data literacy)</strong> \r\n      menjelang <strong>Sensus Ekonomi 2026</strong>.</p>', '/assets/buletin/info-terbaru/Penabur 15052025@2x-100 (1).jpg', '2025-05-15'),
(2, 'BPS Goes to Campus: Komunikasi Data Statistik di Era Digital', ' <p><strong>BPS Provinsi Banten</strong> melaksanakan kegiatan \r\n      <em>BPS Goes To Campus</em> di <em>Universitas Bina Bangsa, Kota Serang</em> \r\n      pada <strong>Rabu, 26 Februari 2025</strong>.</p>\r\n\r\n      <p>Kegiatan menghadirkan kuliah tamu bertajuk \r\n      <strong>“Mengkomunikasikan Data BPS di Media Digital”</strong> bersama \r\n      <em>Humas 3600 BPS</em>.</p>\r\n\r\n      <p><strong>Tujuan:</strong></p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li>Meningkatkan pemahaman strategi komunikasi publik.</li>\r\n        <li>Mengemas dan menyampaikan data statistik melalui platform digital.</li>\r\n        <li>Mendorong literasi statistik di kalangan mahasiswa.</li>\r\n      </ul>\r\n\r\n      <p>Selain teori, juga dibahas:</p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li><em>Best practices</em> storytelling berbasis data.</li>\r\n        <li>Teknik pengolahan konten digital.</li>\r\n        <li>Etika komunikasi publik untuk menjaga kredibilitas.</li>\r\n      </ul>', '/assets/buletin/info-terbaru/Humas 26022025@4x (1).png', '2025-02-26'),
(3, 'Edustat-Talk Series #2 Bahas Pemanfaatan Data Statistik di Sektor Industri', ' <p><strong>Banten, 22 Maret 2025</strong> – <em>Pojok Statistik Nasional</em> \r\n      menggelar <strong>Edustat-Talk Series #2</strong> bertema \r\n      <em>“Utilization of Data in Statistical Administration Activities in Industrial Sector.”</em></p>\r\n\r\n      <p><strong>Narasumber:</strong></p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li>Enang Sumarna, S.Si., M.M. – Statistisi Muda BPS Banten</li>\r\n        <li>Dr. Faula Arina, S.Si., M.Si. – Dosen Statistika Untirta</li>\r\n      </ul>\r\n\r\n      <p><strong>Poin utama:</strong></p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li>Klasifikasi usaha & industri (PP No. 7/2021, Perka BPS No. 45/2018).</li>\r\n        <li>Kontribusi industri Banten: baja, makanan, tekstil, kimia.</li>\r\n        <li>Perbedaan data antar instansi (contoh: pertanian BPS vs ATR/BPN).</li>\r\n        <li>Hilirisasi riset akademik agar berguna dalam kebijakan.</li>\r\n      </ul>\r\n\r\n      <p>Diskusi menegaskan bahwa <strong>data statistik adalah fondasi evidence-based policy</strong>.</p>', '/assets/buletin/info-terbaru/Pamfleet Edustat 2 (1).jpg', '2025-03-22'),
(4, 'Pembinaan Agen Pojok Statistik: Pembuatan Layout Desain Publikasi dan Infografis', ' <p><strong>BPS Provinsi Banten</strong> melaksanakan pembinaan bagi \r\n      <em>Agen Pojok Statistik</em> dengan fokus pada \r\n      <strong>desain layout publikasi</strong>.</p>\r\n\r\n      <p><strong>Materi yang diberikan:</strong></p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li>Penggunaan bahan publikasi.</li>\r\n        <li>Cara membaca data statistik.</li>\r\n        <li>Teknik menyusun informasi menjadi media yang mudah dipahami.</li>\r\n      </ul>\r\n\r\n      <p>Peserta aktif berdiskusi dan mempraktikkan langsung pembuatan desain \r\n      menggunakan data resmi BPS.</p>\r\n\r\n      <p><em>Outcome:</em> agen statistik siap menjadi perpanjangan tangan BPS dalam \r\n      mengedukasi masyarakat tentang pentingnya data.</p>', '/assets/buletin/info-terbaru/pembinaan_agen_LayoutDesignPublikasi.jpeg', '2025-09-01'),
(5, 'EKSOTIK Pojok Statistik UNIBA: Meningkatkan Literasi Statistik Mahasiswa', ' <p><strong>Serang, 10 Desember 2024</strong> – Pojok Statistik UNIBA \r\n      menggelar <em>Edukasi Statistik Tematik (EKSOTIK)</em> dengan tujuan \r\n      memperkuat literasi statistik mahasiswa.</p>\r\n\r\n      <p><strong>Isi kegiatan:</strong></p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li>Penjelasan konsep dasar statistik.</li>\r\n        <li>Proses pengumpulan data.</li>\r\n        <li>Pemanfaatan data dalam pengambilan keputusan.</li>\r\n      </ul>\r\n\r\n      <p>Mahasiswa <strong>antusias</strong>: mendengarkan, mencatat, bertanya, dan berdiskusi.</p>\r\n\r\n      <p>Kegiatan ini memperlihatkan peran data dalam sektor ekonomi, pendidikan, \r\n      dan sosial kemasyarakatan.</p>', '/assets/buletin/info-terbaru/Eksotik 101224 (2).jpeg', '2024-12-10'),
(6, 'Pembinaan Agen Statistik UNIBA', ' <p><strong>Serang, November 2024</strong> – <em>Pojok Statistik UNIBA</em> \r\n      bekerja sama dengan <strong>BPS Provinsi Banten</strong> mengadakan \r\n      <strong>Pembinaan Agen Statistik</strong>.</p>\r\n\r\n      <p><strong>Materi yang diberikan:</strong></p>\r\n      <ul class=\"list-disc pl-6\">\r\n        <li>Cara mengakses data BPS.</li>\r\n        <li>Memahami metodologi statistik.</li>\r\n        <li>Strategi komunikasi data yang mudah dipahami.</li>\r\n      </ul>\r\n\r\n      <p>Mahasiswa aktif bertanya, terutama soal penggunaan data statistik dalam riset \r\n      akademik dan tugas kampus.</p>\r\n\r\n      <p>Kegiatan ini menegaskan pentingnya sinergi perguruan tinggi–BPS dalam \r\n      membangun <strong>generasi melek data</strong>.</p>', '/assets/buletin/info-terbaru/Pembinaan agen 1124 (4).jpeg', '2025-03-20'),
(7, 'Eksotik: Statistik Itu Estetik, Biar Paham Bukan Cuma Posting', ' <ul>\r\n        <li><b>Badan Pusat Statistik (BPS) Provinsi Banten</b> melalui program <i>Eksotik</i> akan menggelar edukasi dan sosialisasi statistik di Universitas Bina Bangsa pada <b>25 Juli 2025</b>.</li>\r\n        <li>Acara ini mengangkat tema <i>“Statistik Itu Estetik: Biar Paham, Bukan Cuma Posting”</i>\r\n          <ul>\r\n            <li>Dihadiri oleh <b>Maulani, S.Stat., M.Si.</b> sebagai narasumber yang berpengalaman di bidang statistik terapan.</li>\r\n            <li>Peserta akan mendapatkan pemahaman mendalam mengenai <i>data driven decision making</i> yang kini menjadi kebutuhan penting di era digital.</li>\r\n            <li>Kegiatan ini juga menekankan pentingnya literasi statistik bagi mahasiswa agar mampu menganalisis informasi secara kritis.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Selain sesi utama, acara akan dilengkapi dengan:\r\n          <ul>\r\n            <li><b>Workshop interaktif</b> untuk melatih keterampilan dasar analisis data.</li>\r\n            <li><b>Sesi tanya jawab</b> yang memungkinkan peserta berdiskusi langsung dengan narasumber.</li>\r\n            <li>Pameran kecil mengenai publikasi resmi BPS, termasuk <i>infografis</i> dan data terbaru Provinsi Banten.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Tujuan utama kegiatan ini adalah:\r\n          <ul>\r\n            <li>Meningkatkan kesadaran bahwa <b>statistik bukan hanya angka</b>, tetapi juga alat komunikasi informasi yang efektif.</li>\r\n            <li>Mendorong mahasiswa untuk lebih aktif memanfaatkan data dalam penelitian maupun karya ilmiah.</li>\r\n            <li>Mengubah pandangan bahwa statistik itu rumit menjadi lebih menarik, sederhana, dan <i>estetik</i>.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>', '/assets/buletin/info-terbaru/Eksotik_(3).png', '2025-07-25'),
(8, 'Kuliah Tamu BPS Provinsi Banten: Tingkatkan Pemahaman Data Statistik', ' <ul>\r\n        <li><b>Badan Pusat Statistik (BPS) Provinsi Banten</b> menggelar <b>kuliah tamu</b> yang diikuti dengan antusias oleh mahasiswa di lingkungan kampus.</li>\r\n        <li>Kegiatan ini menghadirkan tim <b>Humas BPS</b> yang berperan penting dalam menyampaikan informasi publik.\r\n          <ul>\r\n            <li>Mereka berbagi wawasan tentang pentingnya memahami serta mengomunikasikan <i>data statistik</i> secara efektif di <b>era digital</b>.</li>\r\n            <li>Paparan materi mencakup bagaimana data dapat digunakan untuk mendukung <i>evidence-based policy</i> di berbagai bidang.</li>\r\n            <li>Mahasiswa juga diajak memahami cara menghindari kesalahan interpretasi data yang sering terjadi di media sosial maupun publikasi informal.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Antusiasme mahasiswa terlihat dari:\r\n          <ul>\r\n            <li>Banyaknya pertanyaan kritis yang diajukan seputar penggunaan data dalam penelitian dan dunia kerja.</li>\r\n            <li>Diskusi aktif mengenai tantangan menyajikan data dalam bentuk yang lebih <i>user-friendly</i> agar mudah dipahami masyarakat umum.</li>\r\n            <li>Keterlibatan mahasiswa dalam <b>simulasi sederhana</b> mengolah data dan menyajikan hasilnya dalam bentuk <i>infografis</i>.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Selain itu, acara ini juga memberikan manfaat tambahan berupa:\r\n          <ul>\r\n            <li><b>Peningkatan literasi statistik</b> sebagai bekal penting dalam menghadapi banjir informasi di era digital.</li>\r\n            <li><b>Inspirasi karier</b> di bidang statistik, data science, dan komunikasi publik.</li>\r\n            <li>Motivasi agar mahasiswa dapat menjadi agen perubahan yang mampu menyebarkan informasi berbasis data secara akurat.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Melalui kegiatan ini, diharapkan mahasiswa semakin sadar bahwa:\r\n          <ul>\r\n            <li><b>Statistik bukan sekadar angka</b>, tetapi juga sarana untuk menguatkan komunikasi publik dan pengambilan keputusan.</li>\r\n            <li>Kemampuan memahami data akan memberikan <i>nilai tambah</i> dalam studi maupun karier profesional di masa depan.</li>\r\n            <li>Kuliah tamu semacam ini merupakan jembatan penting antara dunia akademik dan lembaga resmi negara.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>', '/assets/buletin/info-terbaru/kuliah_tamu.jpeg', '2025-02-26'),
(9, 'Eksotik: Edukasi Statistik Bersama BPS Provinsi Banten di UNIBA', '  <ul>\r\n        <li><b>Badan Pusat Statistik (BPS) Provinsi Banten</b> melalui program <i>Eksotik</i> menggelar <b>edukasi dan sosialisasi statistik</b> di Universitas Bina Bangsa pada <b>28 November 2024</b>.</li>\r\n        <li>Kegiatan ini menghadirkan <b>Khafid Akhiriyanto</b>, <i>Statistisi Ahli Muda</i> BPS Provinsi Banten.\r\n          <ul>\r\n            <li>Beliau membahas bagaimana cara <b>membunyikan data statistik</b> dengan analisis sederhana agar lebih mudah dipahami oleh masyarakat umum.</li>\r\n            <li>Materi yang disampaikan mencakup pentingnya penyajian data yang jelas, ringkas, dan memiliki nilai praktis.</li>\r\n            <li>Peserta diperkenalkan pada contoh penerapan analisis sederhana yang relevan dengan isu sehari-hari.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Tujuan utama kegiatan ini adalah:\r\n          <ul>\r\n            <li>Meningkatkan pemahaman mahasiswa tentang bagaimana <i>data statistik</i> dapat menjadi sarana komunikasi yang efektif.</li>\r\n            <li>Mendorong generasi muda untuk lebih aktif dalam membaca, menafsirkan, dan menggunakan data dalam pengambilan keputusan.</li>\r\n            <li>Menunjukkan bahwa <b>statistik bukan hanya teori</b>, tetapi juga dapat diterapkan secara langsung dalam kehidupan nyata.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Dengan adanya program ini, diharapkan mahasiswa mampu:\r\n          <ul>\r\n            <li>Mengembangkan keterampilan berpikir kritis berbasis data.</li>\r\n            <li>Menghindari kesalahan dalam memahami informasi yang tersebar di media digital.</li>\r\n            <li>Menjadi agen literasi statistik yang dapat menyebarkan informasi akurat dan bermanfaat.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>', '/assets/buletin/info-terbaru/Khafid_Pojok.png', '2024-11-28'),
(10, 'Eksotik Kolaborasi: Kenalan dengan Statistik Keuangan', ' <ul>\r\n        <li><b>Badan Pusat Statistik (BPS) Provinsi Banten</b> akan menggelar kegiatan <i>Eksotik Kolaborasi</i> pada <b>15 Mei 2025</b> di <b>BPK PENABUR SMAK Penabur Serang</b>.</li>\r\n        <li>Acara ini menghadirkan <b>Rizal Rahadiana</b>, <i>Statistisi Ahli Muda</i> BPS.\r\n          <ul>\r\n            <li>Beliau akan membahas pentingnya memahami <b>statistik keuangan</b> secara lebih dekat.</li>\r\n            <li>Paparan materi dirancang agar siswa dapat melihat bagaimana data keuangan memengaruhi kebijakan publik dan kehidupan sehari-hari.</li>\r\n            <li>Peserta diperkenalkan dengan contoh sederhana mengenai analisis tren keuangan yang mudah dipahami.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Manfaat utama kegiatan ini adalah:\r\n          <ul>\r\n            <li>Meningkatkan literasi siswa mengenai <i>data finansial</i> sebagai bagian penting dari pengelolaan informasi.</li>\r\n            <li>Memberikan gambaran nyata bahwa <b>statistik bukan hanya teori</b>, melainkan juga alat untuk memahami kondisi ekonomi.</li>\r\n            <li>Mendorong generasi muda untuk lebih bijak dalam membaca data keuangan yang tersebar di berbagai media.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Melalui kegiatan ini, diharapkan siswa mampu:\r\n          <ul>\r\n            <li>Mengembangkan keterampilan dalam menganalisis data keuangan sederhana.</li>\r\n            <li>Menyadari peran penting statistik dalam kehidupan modern, khususnya di bidang ekonomi.</li>\r\n            <li>Menjadi generasi yang lebih kritis, analitis, dan peka terhadap isu keuangan berbasis data.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>', '/assets/buletin/info-terbaru/Eksotik@2x-100.jpg', '2025-05-15'),
(11, 'Eksotik: Edukasi Statistik BPS Provinsi Banten di Kampus', '<ul>\r\n        <li><b>Badan Pusat Statistik (BPS) Provinsi Banten</b> melalui program <i>Eksotik</i> kembali hadir memberikan <b>edukasi statistik</b> kepada mahasiswa pada <b>23 Oktober 2024</b>.</li>\r\n        <li>Kegiatan ini berlangsung secara <b>interaktif</b>, menghadirkan suasana belajar yang santai namun tetap penuh wawasan.\r\n          <ul>\r\n            <li>Materi utama berfokus pada pentingnya pemahaman <i>data statistik</i> dalam berbagai bidang kehidupan.</li>\r\n            <li>Peserta diajak memahami bagaimana data dapat menjadi dasar pengambilan keputusan yang lebih objektif.</li>\r\n            <li>Diskusi juga menyoroti contoh nyata penggunaan statistik dalam sektor pendidikan, kesehatan, dan ekonomi.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Nilai tambah dari kegiatan ini antara lain:\r\n          <ul>\r\n            <li><b>Peningkatan literasi data</b> bagi mahasiswa agar lebih siap menghadapi tantangan era digital.</li>\r\n            <li>Latihan singkat mengenai cara membaca <i>infografis</i> dan tabel data resmi BPS.</li>\r\n            <li>Pemaparan strategi sederhana untuk menghindari kesalahan dalam menafsirkan informasi statistik.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Dengan adanya program ini, diharapkan mahasiswa:\r\n          <ul>\r\n            <li>Lebih kritis dalam menganalisis informasi yang beredar di media sosial maupun berita.</li>\r\n            <li>Mampu mengaitkan teori yang dipelajari di kampus dengan <b>praktik nyata</b> di lapangan.</li>\r\n            <li>Termotivasi untuk menjadikan <i>statistik</i> sebagai bekal penting dalam riset, karya ilmiah, maupun karier profesional.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>', '/assets/buletin/info-terbaru/Eksotik_(4).jpeg', '2024-10-23'),
(12, 'Pojok Statistik: Dasar-dasar Infografis', ' <ul>\r\n        <li><b>Badan Pusat Statistik (BPS) Provinsi Banten</b> melalui <i>Pojok Statistik</i> memberikan materi bertajuk <b>Dasar-dasar Infografis</b> dalam kegiatan <b>Pembinaan Agen Statistik 2025</b>.</li>\r\n        <li>Materi ini disampaikan oleh <b>Eben Baenuri</b>, <i>Statistisi Ahli Muda</i> BPS Provinsi Banten, bertempat di <b>Serang</b> pada <b>April 2025</b>.\r\n          <ul>\r\n            <li>Paparan berfokus pada teknik menyusun <i>infografis</i> yang informatif, menarik, dan mudah dipahami masyarakat.</li>\r\n            <li>Peserta dikenalkan pada prinsip dasar desain visual, seperti penggunaan warna, ikon, dan tata letak.</li>\r\n            <li>Materi juga menekankan pentingnya ketepatan data agar pesan yang disampaikan tidak menimbulkan kesalahpahaman.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Tujuan utama dari sesi ini antara lain:\r\n          <ul>\r\n            <li><b>Meningkatkan keterampilan komunikasi statistik</b> bagi para agen statistik agar mampu menyampaikan data dengan cara yang lebih efektif.</li>\r\n            <li>Memberikan pemahaman bahwa <i>infografis</i> adalah jembatan antara data yang kompleks dengan masyarakat umum.</li>\r\n            <li>Melatih peserta untuk menghasilkan karya visual sederhana yang dapat digunakan dalam publikasi resmi maupun media sosial.</li>\r\n          </ul>\r\n        </li>\r\n        <li>Manfaat yang diharapkan dari kegiatan ini:\r\n          <ul>\r\n            <li>Peserta lebih percaya diri dalam mengolah data dan menyajikannya secara visual.</li>\r\n            <li>Terbangunnya budaya <b>literasi statistik</b> yang kuat di kalangan mahasiswa dan agen statistik muda.</li>\r\n            <li>Adanya kontribusi nyata dalam upaya BPS menyebarkan informasi berbasis data yang akurat dan mudah diakses publik.</li>\r\n          </ul>\r\n        </li>\r\n      </ul>', '/assets/buletin/info-terbaru/potik_dasarInfografis.png', '2025-04-23');

-- --------------------------------------------------------

--
-- Table structure for table `tb_infografis`
--

CREATE TABLE `tb_infografis` (
  `id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `desk` text NOT NULL,
  `img` varchar(255) NOT NULL,
  `date` date NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `tb_infografis`
--

INSERT INTO `tb_infografis` (`id`, `title`, `desk`, `img`, `date`) VALUES
(1, 'Kemiskinan di Banten 2024', '<p>\r\n    Berdasarkan data <b>Badan Pusat Statistik (BPS) Provinsi Banten</b> tahun 2024, \r\n    persentase penduduk miskin di Provinsi Banten tercatat sebesar \r\n    <b>5,58%</b>. Angka ini menunjukkan bahwa dari setiap 100 penduduk, \r\n    sekitar 5 hingga 6 orang masih hidup di bawah garis kemiskinan.\r\n  </p>\r\n\r\n  <p class=\"mt-4\">\r\n    Selain itu, terdapat <b>tiga kabupaten</b> dengan persentase penduduk miskin tertinggi di Banten, yaitu:\r\n  </p>\r\n\r\n  <ol class=\"list-decimal pl-6 space-y-2 mt-2\">\r\n    <li><b>Kabupaten Pandeglang</b> – sebesar <b>9,18%</b></li>\r\n    <li><b>Kabupaten Lebak</b> – sebesar <b>8,44%</b></li>\r\n    <li><b>Kabupaten Tangerang</b> – sebesar <b>6,55%</b></li>\r\n  </ol>\r\n\r\n  <p class=\"mt-4\">\r\n    Data ini menggambarkan bahwa meskipun secara umum angka kemiskinan di Banten relatif rendah, \r\n    masih terdapat <b>ketimpangan antarwilayah</b>. \r\n    Pandeglang dan Lebak sebagai wilayah dengan karakteristik pedesaan dan ketergantungan pada sektor pertanian \r\n    menunjukkan angka kemiskinan yang lebih tinggi dibandingkan wilayah lain. \r\n    Sementara itu, Kabupaten Tangerang yang merupakan kawasan penyangga ibu kota juga masih mencatat angka kemiskinan cukup signifikan \r\n    meskipun berada di kawasan industri.\r\n  </p>\r\n\r\n  <p class=\"mt-4\">\r\n    Informasi ini diharapkan menjadi <b>dasar dalam penyusunan kebijakan</b> pemerintah daerah, akademisi, maupun pihak terkait lainnya \r\n    untuk menekan angka kemiskinan melalui <b>program-program yang tepat sasaran</b>, terutama di daerah dengan tingkat kemiskinan tertinggi.\r\n  </p>', '/assets/infografis/Infografis pojok_Kemiskinan@4x.png', '2024-12-01'),
(2, 'Ketenagakerjaan di Banten 2024', '<p>\r\n        Infografis ini menyajikan beberapa fakta penting terkait \r\n        <b>ketenagakerjaan di Provinsi Banten tahun 2024</b> berdasarkan hasil \r\n        Survei Angkatan Kerja Nasional (Sakernas) yang dilakukan oleh \r\n        <b>Badan Pusat Statistik (BPS)</b>.\r\n      </p>\r\n\r\n      <p>\r\n        Berdasarkan lapangan usaha, jumlah penduduk usia 15 tahun ke atas \r\n        yang bekerja di sektor <b>konstruksi</b> mengalami peningkatan terbesar \r\n        dibandingkan tahun sebelumnya, yaitu sekitar <b>113,77 ribu orang</b>. \r\n        Hal ini menunjukkan bahwa pembangunan infrastruktur masih menjadi salah \r\n        satu penggerak utama penyerapan tenaga kerja di Banten.\r\n      </p>\r\n\r\n      <p>\r\n        Dari sisi tingkat pengangguran terbuka (TPT), angka tertinggi tercatat \r\n        pada kelompok penduduk dengan pendidikan <b>SMP</b>, yaitu sebesar \r\n        <b>9,35%</b>. Sementara itu, TPT terendah sebesar <b>2,03%</b> terdapat \r\n        pada kelompok penduduk dengan pendidikan <b>Diploma</b>. Temuan ini menegaskan \r\n        bahwa semakin tinggi jenjang pendidikan seseorang, semakin besar pula \r\n        peluangnya untuk masuk ke dunia kerja.\r\n      </p>\r\n\r\n      <p>\r\n        Jika ditinjau dari sektor usaha, terdapat dua sektor yang mendominasi \r\n        penyerapan tenaga kerja, yakni:\r\n      </p>\r\n      <ol class=\"list-decimal pl-6 space-y-2 mt-2\">\r\n        <li><b>Perdagangan</b> – sebesar <b>21,37%</b></li>\r\n        <li><b>Industri Pengolahan</b> – sebesar <b>19,22%</b></li>\r\n      </ol>\r\n\r\n      <p>\r\n        Lebih lanjut, dari total sekitar <b>5,8 juta orang</b> yang bekerja di Banten, \r\n        sekitar <b>50,54%</b> di antaranya berstatus sebagai \r\n        <b>buruh/karyawan/pegawai</b>. Hal ini menunjukkan bahwa sebagian besar pekerja \r\n        di Banten masih berada pada sektor formal, dengan hubungan kerja yang lebih \r\n        terstruktur dibandingkan pekerja mandiri atau sektor informal.\r\n      </p>\r\n\r\n      <p>\r\n        Secara keseluruhan, data ini memberikan gambaran bahwa \r\n        <b>konstruksi, perdagangan, dan industri pengolahan</b> masih menjadi sektor strategis \r\n        dalam penyerapan tenaga kerja di Banten. Namun, tantangan tetap ada terutama pada \r\n        kelompok berpendidikan rendah, yang memiliki tingkat pengangguran terbuka lebih tinggi. \r\n        Informasi ini diharapkan menjadi landasan bagi pemerintah daerah, akademisi, dan pemangku \r\n        kepentingan lainnya dalam menyusun program peningkatan kualitas tenaga kerja melalui \r\n        <b>pendidikan, pelatihan, serta penciptaan lapangan kerja yang lebih produktif dan berkelanjutan</b>.\r\n      </p>', '/assets/infografis/Infografis Naker@4x.png', '2024-11-29'),
(3, 'Perkembangan Ekspor Nonmigas Banten 2025', '<p>\r\n        Infografis ini menyajikan perkembangan <b>nilai ekspor komoditas utama nonmigas</b> \r\n        di Provinsi Banten pada periode <b>Januari–Mei 2025</b>. \r\n        Data menunjukkan adanya dinamika signifikan pada beberapa komoditas unggulan \r\n        serta negara tujuan ekspor utama.\r\n      </p>\r\n\r\n      <p>\r\n        Berdasarkan data, <b>Kakao/Coklat</b> mengalami peningkatan terbesar dengan nilai \r\n        ekspor sebesar <b>494,36 juta US$</b> atau naik <b>369,46%</b> dibandingkan periode yang sama tahun 2024. \r\n        Sementara itu, <b>Plastik dan Barang dari Plastik</b> mencatat nilai ekspor sebesar \r\n        <b>467,22 juta US$</b> namun mengalami sedikit penurunan sebesar <b>0,02%</b>. \r\n        Komoditas <b>Alas Kaki</b> menurun cukup signifikan, dengan nilai ekspor \r\n        <b>422,22 juta US$</b> atau turun <b>52,67%</b>.\r\n      </p>\r\n\r\n      <p>\r\n        Dari sisi negara tujuan, terdapat tiga negara utama dengan pangsa ekspor terbesar:\r\n      </p>\r\n\r\n      <ol class=\"list-decimal pl-6 space-y-3\">\r\n        <li>\r\n          <b>Amerika Serikat</b> – pangsa <b>15,72%</b> atau senilai \r\n          <b>US$823,29 juta</b>, dengan komoditas utama:\r\n          <ul class=\"list-disc pl-6\">\r\n            <li>Kakao/Coklat: <b>US$108,10 juta</b> (13,13%)</li>\r\n            <li>Alas Kaki: <b>US$107,49 juta</b> (13,05%)</li>\r\n            <li>Ikan dan Udang: <b>US$90,18 juta</b> (10,94%)</li>\r\n          </ul>\r\n        </li>\r\n        <li>\r\n          <b>Tiongkok</b> – pangsa <b>11,48%</b> atau senilai \r\n          <b>US$601,40 juta</b>, dengan komoditas utama:\r\n          <ul class=\"list-disc pl-6\">\r\n            <li>Tembaga: <b>US$160,54 juta</b> (26,69%)</li>\r\n            <li>Lemak & Minyak Hewan: <b>US$83,22 juta</b> (13,53%)</li>\r\n            <li>Alas Kaki: <b>US$47,58 juta</b> (7,91%)</li>\r\n          </ul>\r\n        </li>\r\n        <li>\r\n          <b>India</b> – pangsa <b>8,93%</b> atau senilai \r\n          <b>US$467,65 juta</b>, dengan komoditas utama:\r\n          <ul class=\"list-disc pl-6\">\r\n            <li>Bahan Kimia Organik: <b>US$139,58 juta</b> (29,83%)</li>\r\n            <li>Kakao/Coklat: <b>US$107,87 juta</b> (23,05%)</li>\r\n            <li>Plastik dan Barang dari Plastik: <b>US$38,14 juta</b> (10,75%)</li>\r\n          </ul>\r\n        </li>\r\n      </ol>\r\n\r\n      <p>\r\n        Temuan ini menegaskan bahwa <b>Kakao/Coklat</b> menjadi motor utama peningkatan ekspor Banten tahun 2025, \r\n        sementara <b>Alas Kaki</b> mengalami penurunan yang cukup tajam. \r\n        Dari sisi negara tujuan, <b>Amerika Serikat, Tiongkok, dan India</b> masih menjadi \r\n        mitra dagang terbesar, sehingga penguatan akses pasar ke tiga negara tersebut \r\n        menjadi sangat penting untuk menjaga tren positif ekspor Banten.\r\n      </p>', '/assets/infografis/Ekspor2@3x-100.jpg', '2024-11-28'),
(4, 'Keadaan Iklim Banten 2023', '<p>\r\n      Berdasarkan hasil pengamatan iklim di <b>Provinsi Banten</b> sepanjang tahun <b>2023</b>, \r\n      terdapat beberapa indikator penting yang mencerminkan kondisi iklim secara umum. \r\n      Informasi ini tidak hanya bermanfaat bagi masyarakat, namun juga menjadi dasar \r\n      bagi pemerintah daerah, akademisi, dan berbagai pihak terkait dalam menyusun \r\n      strategi adaptasi dan mitigasi perubahan iklim. Berikut adalah rincian indikator utama:\r\n    </p>\r\n\r\n    <ol class=\"list-decimal pl-6 space-y-4\">\r\n      <li>\r\n        <b>Suhu Rata-rata</b> tercatat sebesar <b>27,30 °C</b>. \r\n        <ul class=\"list-disc pl-6\">\r\n          <li>Suhu ini menunjukkan bahwa Banten termasuk wilayah dengan iklim hangat.</li>\r\n          <li>Kondisi ini relatif stabil dibandingkan tahun-tahun sebelumnya, meskipun \r\n              fluktuasi harian tetap terjadi akibat perbedaan siang dan malam.</li>\r\n          <li>Jika tren peningkatan suhu global berlanjut, wilayah Banten berpotensi \r\n              menghadapi suhu ekstrem yang dapat memengaruhi kesehatan dan produktivitas.</li>\r\n        </ul>\r\n      </li>\r\n\r\n      <li>\r\n        <b>Kelembaban Rata-rata</b> mencapai <b>80,42%</b>.\r\n        <ul class=\"list-disc pl-6\">\r\n          <li>Tingkat kelembaban tinggi ini mencerminkan karakteristik iklim tropis \r\n              yang basah dan lembab.</li>\r\n          <li>Kelembaban tinggi dapat memperbesar risiko tumbuhnya jamur, penyakit \r\n              kulit, serta berdampak pada kualitas udara dalam ruangan.</li>\r\n          <li>Bagi sektor pertanian, kelembaban yang konsisten menjadi keuntungan \r\n              karena mendukung pertumbuhan tanaman, namun juga berisiko \r\n              meningkatkan hama tertentu.</li>\r\n        </ul>\r\n      </li>\r\n\r\n      <li>\r\n        <b>Rata-rata Kecepatan Angin</b> sebesar <b>3,46 knot</b>.\r\n        <ul class=\"list-disc pl-6\">\r\n          <li>Kecepatan ini tergolong normal dan masih berada dalam kategori aman \r\n              untuk aktivitas sehari-hari maupun transportasi laut.</li>\r\n          <li>Namun, adanya periode tertentu dengan kecepatan angin yang lebih tinggi \r\n              berpotensi memengaruhi aktivitas pelayaran, perikanan, dan sektor logistik.</li>\r\n          <li>Kecepatan angin yang stabil juga penting untuk mendukung potensi \r\n              pengembangan energi terbarukan, khususnya energi angin.</li>\r\n        </ul>\r\n      </li>\r\n\r\n      <li>\r\n        <b>Rata-rata Tekanan Udara</b> tercatat sebesar <b>1.005,29 mbar</b>.\r\n        <ul class=\"list-disc pl-6\">\r\n          <li>Tekanan udara ini berada dalam kisaran normal untuk wilayah dataran rendah \r\n              dekat permukaan laut.</li>\r\n          <li>Kestabilan tekanan udara sangat berpengaruh terhadap pola cuaca, \r\n              termasuk pembentukan awan dan potensi curah hujan.</li>\r\n          <li>Fluktuasi tekanan yang tajam dapat menandakan perubahan cuaca ekstrem \r\n              seperti badai atau hujan deras.</li>\r\n        </ul>\r\n      </li>\r\n    </ol>\r\n\r\n    <p>\r\n      Secara keseluruhan, kondisi iklim Banten tahun 2023 menunjukkan karakteristik \r\n      tropis dengan suhu hangat, kelembaban tinggi, angin yang relatif stabil, serta \r\n      tekanan udara normal. Informasi ini diharapkan dapat mendukung kebijakan \r\n      pembangunan berkelanjutan, penelitian akademis, serta langkah antisipasi terhadap \r\n      dampak perubahan iklim di masa mendatang.\r\n    </p>', '/assets/infografis/KamisInfografis@4x.png', '2024-11-27');

